'use strict';
const cv = document.getElementById('game');
const ctx = cv.getContext('2d');
// Logical board size — captured from the HTML attributes (900×560) BEFORE any
// high-DPI resize below, so all game logic (paths, coords, clicks) stays in this
// fixed logical space no matter the device pixel ratio.
const W = cv.width, H = cv.height;

// High-DPI canvas (v1.17.0): the backing store defaults to the logical W×H, so on
// Retina / 4K / 150%-scaled Windows displays the browser upsamples it and towers /
// text render slightly soft. Size the backing store to W·dpr × H·dpr and scale the
// context once, so every draw call keeps using logical 0..W / 0..H coords while the
// pixels are crisp. The CSS pins the display box to the logical size (canvas rule
// `width:900px; height:auto`), so this never changes layout. dpr is capped at 2 to
// bound the fill cost on huge ratios, and skipped entirely at dpr=1 (standard
// displays + the headless test harness → byte-identical behaviour). Input is
// unaffected: pointer/click coords are derived from getBoundingClientRect().
const DPR = Math.max(1, Math.min(2, (typeof window !== 'undefined' && window.devicePixelRatio) || 1));
if (DPR > 1) {
  cv.width = Math.round(W * DPR);
  cv.height = Math.round(H * DPR);
  ctx.scale(DPR, DPR);   // persists across frames — draw() never resets the transform
}

// Accessibility: honour the OS "reduce motion" setting — when on, the render loop
// skips screen-shake (the most motion-sensitive effect). Read live so toggling the
// OS setting takes effect without a reload; guarded for environments w/o matchMedia.
let _rmQuery = (typeof window !== 'undefined' && window.matchMedia)
  ? window.matchMedia('(prefers-reduced-motion: reduce)') : null;
function reduceMotion() { return !!(_rmQuery && _rmQuery.matches); }

// Touch ergonomics (v1.16.3): detect a coarse pointer (finger) so the canvas tap
// handler can use a more generous tower-tap radius — on a phone the board scales to
// ~374px (logical 900), so an 18px logical hit radius is only ~7px on screen, making
// towers hard to select. Read live (a 2-in-1 can switch), guarded for no-matchMedia.
let _cpQuery = (typeof window !== 'undefined' && window.matchMedia)
  ? window.matchMedia('(pointer: coarse)') : null;
function coarsePointer() { return !!(_cpQuery && _cpQuery.matches); }

// User render/performance prefs (Settings panel, v1.13.0) — persisted on this device,
// independent of the OS reduce-motion gate. shakeEnabled gates screen-shake;
// particleDensity (1=Full, 0.5=Reduced, 0=Off) scales burst particle counts.
let shakeEnabled = localStorage.getItem('cd_shake') !== '0';   // default ON
let particleDensity = (() => {
  const v = localStorage.getItem('cd_particles');
  return v === null ? 1 : Math.max(0, Math.min(1, +v || 0));
})();
// Colorblind aid (Settings panel, v1.18.0) — when ON, the enemy kinds that are
// currently distinguished by HUE ONLY (fast=purple, tank=orange) also render a
// distinct symbol, so every kind reads as a unique glyph rather than a colour.
// Persisted on this device, default OFF. See enemyGlyph() in cd-render.js.
let colorblindAid = localStorage.getItem('cd_colorblind') === '1';

// Grid placement (Settings panel, v1.24.0 — owner FEEDBACK "the spaces to place the
// turrets were more of a grid so you could line them up cleaner"). When ON, a tower's
// placement point snaps to the centre of a PLACE_GRID cell, so towers align into tidy
// rows/columns. PLACE_GRID === the 32px minimum placement gap, so cells in adjacent rows/
// columns are exactly 32 apart and stay placeable (canPlace forbids < 32). Persisted on
// this device, default ON (the owner asked for it). Selection still uses the raw cursor;
// only the placement target snaps. Cosmetic/UX only — no economy/save impact.
let gridSnap = localStorage.getItem('cd_gridsnap') !== '0';   // default ON
const PLACE_GRID = 32;
function snapGridCoord(v) { return Math.floor(v / PLACE_GRID) * PLACE_GRID + PLACE_GRID / 2; }
function placeCoord(x, y) { return gridSnap ? { x: snapGridCoord(x), y: snapGridCoord(y) } : { x, y }; }

// ================= Version & What's New =================
const GAME_VERSION = 'v1.73.0';
// Most recent first. Show the FULL history (owner preference, v1.13.5 — do not trim
// to a recent-N window; the panel scrolls). Mirrors CHANGELOG.md headings.
const CHANGELOG_ENTRIES = [
  { v: 'v1.73.0', date: '2026-06-15', time: '21:30 EDT', body: "New content — a new legendary perk: 🔥 Killing Spree. Legendary perks are the rare, run-defining picks you draft every five waves, and this is the FIRST one to plug into the kill-streak COMBO meter — until now a purely cosmetic flourish in the corner of the board. While you hold Killing Spree and a combo is hot, EVERY tower hits harder, scaling with your streak: +1% damage per combo, up to +25% at a blazing 25× chain. The payoff is pure game-feel — your whole defense spikes in power exactly when you're already chaining kills, turning a good streak into a snowball of carnage and rewarding aggressive, well-timed clears. But it's deliberately conditional and self-limiting: the combo window is only two seconds, so the instant your streak stalls (or a wave starts leaking past you) the bonus evaporates back to nothing. That makes it strictly weaker than the unconditional 💎 Diamond Core (+30% all the time), so it's a meaningful, build-flavoring draft choice rather than power creep — it can't simply make a struggling run easier, in keeping with the long-running 'too easy' balance work. It pairs naturally with the 🩸 Weak targeting mode (secure more kills, hotter streaks) and the 💀 Reaper execute (faster finishes feed the chain), and it boosts every tower type, including Tesla's chain lightning and Poison's damage. Fully additive and save-safe: a new run-only perk effect with no impact on your saves, chips, gold, or any existing balance, and the 🎲 Wildcard gamble perk can roll it too. (Legendary perk pool grows by one.)" },
  { v: 'v1.72.0', date: '2026-06-15', time: '20:05 EDT', body: "New content — a 16th Mayhem wave modifier: 🫥 Cloaking Field. When it rolls, the WHOLE wave learns the phantom's trick: every enemy (and the boss) periodically phases out for a fraction of a second, becoming briefly untargetable and immune — so a shot that lands while it's cloaked simply misses. It's the wave-wide cousin of the ghostly Phantom enemy, on a pressure axis no other modifier touches: sustained coverage and uptime. Slow, hard-hitting single-target towers (Sniper, Cannon, Mortar) suffer most — they can waste a big shot on a target that blinks out — while rapid-fire towers barely notice. Watch for the violet ring (it flares bright the instant an enemy cloaks, and the enemy fades) so you can read the rhythm. It's deliberately bounded and fair: unlike the Phantom it does NOT teleport enemies forward, and it adds no extra health or speed — it only removes your ability to hit them ~18% of the time, so it can never make a run easier (it leans into the long-running 'too easy' feedback). A Time Freeze pauses the cloak cycle, and an enemy frozen mid-cloak always becomes hittable again. Mayhem / Daily-only, purely run-time — no effect on your saves, chips, talents, or any existing balance. (Wave modifiers: 15 → 16.)" },
  { v: 'v1.71.1', date: '2026-06-15', time: '18:10 EDT', body: "Under the hood — the game now has continuous integration. A new GitHub Actions workflow runs the full automated test suite (800+ checks) on every push and pull request, so any change that would break the game gets caught before it ships. This is purely developer tooling — it doesn't touch the game itself, which still has no build step and still plays by double-clicking the HTML file. Nothing in gameplay, your saves, chips, talents, or balance changes." },
  { v: 'v1.71.0', date: '2026-06-15', time: '16:30 EDT', body: "New content — a 9th boss archetype: 💰 Siphon. From wave 20 on, each every-5th-wave boss carries a special mechanic, and the deep bosses cycle through them; Siphon is the newest, and it pressures something no other boss touches — your WALLET. While a Siphon boss is alive on the field it drains a small, wave-scaled chunk of your gold every few seconds (more on later waves), shown as a gold ‘-N💰’ pop over the boss with a draining sound. It's a fresh ECONOMIC axis — every other archetype hardens the late game through health, speed, shields, summons, blink, crowd-control immunity or knocking your towers offline; this one bleeds your bank, so you can't just farm your way through a tough boss wave. It leans straight into the long-running 'too easy / money snowballs early' balance feedback: the answer to a Siphon is to kill it FAST before it bleeds you, which rewards focused fire and burst damage. It's deliberately bounded and fair — the drain is floored at zero (it can never push you negative or soft-lock you, and your kills still pay full bounty), it only fires once every ~3.5s, and like every boss mechanic a Time Freeze pauses it entirely. The boss wears a gold aura ring and a SIPHON banner on its health bar so you know what you're up against. Pure run-time behaviour — no effect on your saves, chips, talents, or any existing balance. (Boss archetypes: 8 → 9.)" },
  { v: 'v1.70.1', date: '2026-06-15', time: '15:40 EDT', body: "🩺 Health check (every 6th run) — no new feature this time; this is the routine tune-up that keeps the game healthy. Ran the full automated test suite: all 823 checks across 80 groups passed with zero console errors, in about 18 seconds. Confirmed the game still plays by double-clicking the file with no web server (the offline service-worker registration stays correctly disabled in that mode). Verified that an old save from before recent features still loads cleanly through the migration defaults — your chips, talents, achievements and records are safe. Read the design docs against the actual code: the tower targeting modes (6), active abilities (4), Mayhem wave modifiers (15), boss archetypes (8), tower types (8) and achievements (15) all match what's documented, and the offline-cache version is back in sync with the game version. The only drift found was a stale line in the internal roadmap about the test file's size, now corrected. No gameplay, balance, economy, or save changes." },
  { v: 'v1.70.0', date: '2026-06-15', time: '14:30 EDT', body: "New content — a 6th tower targeting mode: 🩸 Weak. Every non-booster tower has a little targeting button in its upgrade panel that decides which enemy it shoots when several are in range — ⏩ First, ⏪ Last, 💪 Strong (highest HP), 📍 Close, and 🛡 Support (pop the healers/wardens). Weak is the missing FINISHER: a tower set to Weak always fires at the lowest-HP enemy in range, securing kills instead of spreading damage around. That sounds minor but it's a real tactical lever, and it leans straight into two systems you already love — the kill-streak COMBO meter (more confirmed kills per second = longer, hotter streaks and bigger board glow) and the new 💀 Reaper execute perk (Weak towers tee up wounded enemies for the execute). It's also the natural counterpart to 💪 Strong: pair a heavy hitter on Strong to crack the tanks while a fast tower on Weak mops up the stragglers so nothing limps past your line. When two enemies are equally hurt, Weak breaks the tie toward whichever is furthest along the path, so it quietly prioritises the one most likely to leak. Fully additive and save-safe — the mode list auto-wires everywhere (shop, cycle button, save/resume), and old saves load unchanged; a tower with an unknown saved mode falls back to First as always. No balance, economy, or save-schema impact. (Targeting modes: 5 → 6.)" },
  { v: 'v1.69.0', date: '2026-06-15', time: '13:20 EDT', body: "Polish — the start menu now has an ATMOSPHERE. Until now the screen you see before a run was a flat, near-black sheet; it now sits over a soft, slow-drifting ambient glow in the game's circuit palette — cool blue, teal and a touch of violet that breathe gently across the panel, like light pooling behind the menu. It's purely cosmetic, but it makes the start screen read as a designed, lived-in panel rather than an empty void, and it pairs with the existing PLAY-button glow/glint to draw the eye to the one live action. The motion is deliberately gentle (a 22-second cycle) and, like every other animation in the game, it freezes automatically if your system is set to reduce motion — the colour stays, only the drift stops. It's the next slice of the ongoing 'revamp the starting menu' work (after the button hierarchy, the animated PLAY button, the config card, and the hero header), and it touches nothing but the start screen's backdrop: no effect on the game board, your saves, chips, gold, or any balance. (Menu-revamp slice 5.)" },
  { v: 'v1.68.0', date: '2026-06-15', time: '00:14 EDT', body: "New content — a new legendary perk: ⏱️ Hair Trigger. Legendary perks are the rare, run-defining picks you draft every five waves, and this one is a build-altering TRADE-OFF — the mirror image of 🔮 Glass Cannon. Where Glass Cannon trades reach for raw punch (+50% damage, −30% range), Hair Trigger trades punch for SPEED: every tower fires +55% faster but deals −25% damage per shot. The net result is only a modest damage gain (about +16%), so it's deliberately NOT power creep — instead it completely changes how a build FEELS and what it's good at. Fast, splashy, rapid-fire towers love it (more shots means more splash coverage, faster combos, and quicker reactions to leaks), while slow heavy hitters like the Cannon, Sniper and Mortar give up the very burst that makes them good. There's a real downside, too: because each shot lands softer, flat enemy ARMOR eats a bigger slice of it, so Hair Trigger is noticeably WORSE against armored and shielded enemies and late-game bosses — exactly where you might want raw punch instead. So it's a genuine choice at the draft, not a free upgrade, and it can't simply make a run easier. Fully additive and save-safe: a new run-only perk effect with no impact on your saves, chips, gold, or any existing balance, and the 🎲 Wildcard gamble perk can roll it too. (Legendary perk pool grows by one.)" },
  { v: 'v1.67.0', date: '2026-06-14', time: '23:59 EDT', body: "New content — a 4th active ability: 🌀 Shockwave (hotkey R, or the right trigger on a gamepad). Abilities are the powerful, cooldown-gated buttons in the top-right of the board; you've had three (☄️ Meteor, 🧊 Time Freeze, 💰 Gold Rush) since the early days, and Shockwave is the first new one in ages. When you fire it, a kinetic blast knocks EVERY enemy on the field backward along the path — rewinding their progress toward your base and re-exposing them to your towers' fire. It's a panic button and a repositioning tool, deliberately distinct from Time Freeze: Freeze pauses enemies where they stand, Shockwave shoves them back the way they came (with a brief stagger), so it's perfect for catching a wave that's about to leak or buying your towers another pass at a cluster. It's pure utility — it deals NO damage — so it adds tactical depth and chunky game-feel without making the game easier (no power creep, in keeping with the 'too easy' balance work). Bosses get shoved a smaller distance (they're not so easily pushed around), and crowd-control-immune enemies — those under the 🔥 Heatwave wave modifier, and the 🟦 Juggernaut boss — completely shrug it off, reinforcing the crowd-control axis those mechanics are built on. Like every ability its cooldown isn't saved, so it's fully save-safe; old saves load with the new ability ready to go. (Active ability count: 3 → 4.)" },
  { v: 'v1.66.0', date: '2026-06-14', time: '23:59 EDT', body: "New content — a 15th Mayhem wave modifier: 🔥 Heatwave. When it rolls on a Mayhem (or Daily Challenge) wave, the whole pack runs HOT: every enemy and boss becomes immune to crowd control, shrugging off your Freeze ability and your Frost towers' slow entirely for that wave. It's a brand-new axis no other modifier touches — none of the previous fourteen affect slow/freeze — and it's the wave-wide cousin of the Juggernaut boss's signature trick. The pressure it creates is pointed: a defense that leans on freezing or slowing the path to buy time suddenly has to lean on raw damage instead, so it's a clean check on the strong Frost / booster snowball without nerfing anything permanently. It's deliberately bounded so it's challenging, not unfair: a Heatwave adds no extra health or speed — it only takes away YOUR crowd-control advantage that wave — so it can never make a run easier, only test whether your build can actually kill, not just stall. A warm orange ring marks each immune enemy so you can see at a glance why your Frost towers aren't biting. Mayhem-only, pure run-time behaviour — no effect on your saves, chips, gold, or any existing balance. (Mayhem modifier pool is now 15.)" },
  { v: 'v1.65.1', date: '2026-06-14', time: '21:13 EDT', body: "🩺 Health check (the every-6th-run maintenance pass — no new feature this time, just confirming everything is still solid). The full automated test suite passes (769 assertions across 75 groups, zero failures) with zero console errors, and the game still loads and plays by double-clicking the file — classic script tags in the right order, no ES modules, inline favicon, no build step, all paths relative, so offline play is intact. Old saves still migrate cleanly (a minimal pre-update save loads via the additive defaults: talents/achievements/stats/bestCombo, perk state, map theme). Checked the maintainer docs against the actual code — every number still matches: 8 towers, 8 boss archetypes, 14 Mayhem wave modifiers, 15 achievements, the boss HP slope (×0.6/wave), the boss armor slope (×0.5/wave) and the enemy-HP curve. Versions are consistent everywhere (v1.65.1). All game source files stay well under the size cap (largest ~1,008 lines, cd-update.js) with no dead code, debug logging, or TODOs. Refreshed the test-harness-size roadmap note (now 4,784 lines / 75 groups / 769 assertions, was 73 groups). Table-stakes checklist remains complete (only open follow-ups: a raster PNG icon set for stricter PWA installability audits, and a CI workflow — both already filed)." },
  { v: 'v1.65.0', date: '2026-06-14', time: '23:59 EDT', body: "New content — a brand-new legendary perk: 💀 Reaper. Legendary perks are the rare, run-defining picks you draft every five waves, and this one is an EXECUTE: while you hold Reaper, any non-boss enemy your towers knock below 12% of its health is instantly destroyed — no waiting for that last sliver to whittle down. A 💀 EXECUTE pops over each finished foe, so weakened swarms vanish in a satisfying cascade, and because the kill routes through the normal death path it still feeds your gold, your kill-streak combo, and the Overkill perk if you also hold it (a Reaper-execute can trigger an Overkill detonation, chaining a whole cluster). It's deliberately bounded so it's powerful, not broken: BOSSES are exempt — the real difficulty of a run is untouched — and it only shaves the tail off trash you'd have killed a beat later anyway, so it's a modest, chunky damage boost (well below a flat +30% all-damage legendary), not a run-warping one. It pairs especially well with high-rate towers that struggle to land the finishing blow on a healthy enemy but love to chip a swarm down to the execute line. Fully additive and save-safe: it's a new run-only perk effect with no impact on your saves, chips, gold or any existing balance, and the 🎲 Wildcard gamble perk can now roll it too. (Legendary perk pool grows by one.)" },
  { v: 'v1.64.0', date: '2026-06-14', time: '23:59 EDT', body: "Balance — bosses now wear HEAVIER ARMOR late in a run, so the climactic every-fifth-wave fight stays a real threat instead of melting. A boss's armor now scales a bit faster with wave number (the same way the shielded enemy's already does), which raises the difficulty exactly where the game was starting to feel too easy — the late-game plateau — without touching early waves or any enemy's health. The clever part is WHO it hits: armor is flat damage reduction, so it barely slows your big-hitting towers (a Cannon or Sniper kills the boss only a couple of percent slower), and it's completely ignored by your anti-armor tools — the Mortar and the gun's Armor-Piercing spec punch straight through it, and Poison corrodes it away over time. What it DOES bite is the cheap, spammy high-fire-rate / low-damage build (a wall of basic guns) that was trivializing the late game: that build's boss kill is now meaningfully slower (about +6% by wave 20, +10% by wave 30, +25% by wave 50). In short, it nudges you toward smarter, more varied builds and gives the anti-armor towers a real job, rather than just making every boss a bigger sponge. The change is a modest, simulated tweak (the armor number rises 25%, right at the per-run balance cap, and a single leveled gun still kills the boss — just slower, so it stays beatable), and it's purely run-time enemy stats: no effect on your saves, chips, gold, talents, or tower balance." },
  { v: 'v1.63.0', date: '2026-06-14', time: '23:55 EDT', body: "New content — a new enemy type: the ‼ Breacher. From wave 17 onward, a hulking dark-red unit (marked with a ‼ and a faint red warning ring) lumbers down the path among the rest of the wave. It's slow and not especially tough, but it carries a nasty threat: if a Breacher reaches the exit, it costs you TWO lives instead of one. That's a brand-new kind of pressure — until now every regular enemy that leaked cost a single life, and only bosses hit harder — so a Breacher slipping through a gap in your coverage hurts twice as much. It rewards solid, gap-free defenses and punishes the lazy chokepoint, and crucially it shows up in EVERY mode (Classic, Campaign and Mayhem), not just the deep boss waves — a gentle, broad answer to the game feeling too easy in the early modes. Because it's slow and only moderately healthy, a competent defense stops it cold; the danger is purely about not letting one leak. It pays a generous bounty when you do kill it, the next-wave preview and threat number both count it so you can see it coming, and it carries its own symbol for the colorblind aid. Pure run-time enemy behaviour — no effect on your saves, chips, gold, talents, or any existing balance." },
  { v: 'v1.62.0', date: '2026-06-14', time: '22:55 EDT', body: "Clarity — the end-of-run screen can now SHOW ITS WORK. Every run earns a score (how far you got, how clean, how rich, scaled by difficulty), but until now the single number just appeared with no explanation of where it came from. There's now a discreet '▸ Score breakdown' link under the score: click it and a tidy table unfolds showing exactly how the total was built — points from waves cleared, kills, lives kept, gold banked, your best combo, campaign depth and the victory bonus, then the running subtotal, your difficulty multiplier (Easy ×0.5 / Normal ×1 / Hard ×1.6) and the efficiency multiplier (using ≤10 towers earns up to +30%), and finally the score. It makes the 'fewer towers, bigger combos, more gold' levers legible, so you can see which choices actually move your score and chase a better grade on purpose. It stays collapsed by default so the screen reads just as cleanly as before — it's purely a display of numbers the game already computes, with no effect on gameplay, balance, your saves, chips or gold." },
  { v: 'v1.61.0', date: '2026-06-14', time: '21:40 EDT', body: "Progression — the 🏆 Records panel now tracks your BEST SCORE, not just your deepest wave. Every run already earns a score (how far you got, how clean, how rich, scaled by difficulty) shown on the end screen, but it used to vanish the moment you left — only a single all-time best was kept behind the scenes. Now the Records panel shows two grids: your highest wave per map and difficulty (as before), and a new 🏆 Best scores grid right below it — your top score for each map × difficulty in quick play — plus your all-time best score in the footer stats. So there's a fresh reason to replay a map you've already beaten: not just to survive one wave deeper, but to post a cleaner, higher-scoring run (fewer towers, bigger combos, more gold banked). Fully additive and save-safe — new per-map score keys default to nothing on existing saves and fill in as you play; no effect on gold, chips, balance, or your existing records. Campaign (random maps) and the Daily Challenge (its own seed) don't post per-map scores, matching how best-wave already works." },
  { v: 'v1.60.1', date: '2026-06-14', time: '20:10 EDT', body: "🩺 Health check (the every-6th-run maintenance pass — no new feature this time, just confirming everything is still solid). The full automated test suite passes (709 assertions across 71 groups, zero failures) with zero console errors, and the game still loads and plays by double-clicking the file — classic script tags in the right order, no ES modules, inline favicon, no build step, all paths relative, so offline play is intact. Old saves still migrate cleanly (a minimal pre-update save loads via the additive defaults: talents/achievements/stats, perk state, map theme). Checked the maintainer docs against the actual code — every number still matches: 8 towers, 8 boss archetypes, 14 Mayhem wave modifiers, 15 achievements, the boss HP slope (×0.6/wave) and the enemy-HP curve. Versions are consistent everywhere (v1.60.1). All game source files stay well under the size cap (largest ~942 lines) with no dead code, debug logging, or TODOs. Fixed one stale doc note (the test-harness line said the shipped game is 'three raw files' — it's been HTML + CSS + seven JS files + the PWA trio since the v1.8.2 domain split) and refreshed the test-harness-size roadmap entry (now 4,484 lines / 71 groups). Table-stakes checklist remains complete." },
  { v: 'v1.60.0', date: '2026-06-14', time: '18:05 EDT', body: "Game feel — a new COMBO BOARD GLOW rewards aggressive play. Chaining kills already builds the bottom-right combo meter, which glows hotter as your streak climbs (green → gold → orange → red → purple). Now the whole board joins in: once your streak passes the first milestone (10×), the edges of the playfield start to breathe with the combo-tier colour, and that glow escalates as the chain grows — a subtle gold shimmer at 10×, deepening through orange and red, blazing purple at a monstrous 50× streak. It's pure spectacle that makes a hot streak FEEL hot: the longer you keep the kills rolling, the more the screen lights up around you, and it fades the instant the chain breaks. It's entirely cosmetic — no effect on damage, gold, chips, your saves, or balance of any kind. And it respects your settings: it pulses, so turning ✨ Particle effects to Reduced dials it down, Off switches it off completely, and the OS 'reduce motion' setting suppresses it too — exactly like every other juice effect in the game." },
  { v: 'v1.59.0', date: '2026-06-14', time: '16:40 EDT', body: "New content — a brand-new legendary perk: 💢 Overkill. Legendary perks are the rare, run-defining picks you draft every five waves, and this one is a chunky chain-reaction: whenever an enemy dies while you hold Overkill, it DETONATES, splashing 25% of its maximum health as armor-ignoring damage to every nearby enemy. Land a clean kill in the middle of a packed swarm and the whole cluster can light up at once — a satisfying, screen-shaking sweep that turns tightly-bunched waves into a fireworks show. Because the splash scales with the slain enemy's max HP, it stays relevant deep into a run (a fat tank's death is a big bomb), and it pairs beautifully with the kill-streak combo meter — faster clears mean longer streaks. It's deliberately bounded so it's powerful, not broken: only the original killing blow detonates (a chain-killed enemy doesn't set off a second explosion), so you still have to do the real work of dropping each 'seed' enemy yourself — it just finishes their neighbours. Bosses don't detonate. Fully additive and save-safe: it's a new run-only perk effect, so it has no impact on your saves, chips, gold or any existing balance, and the Wildcard gamble perk can now roll it too. (Legendary perk pool grows by one.)" },
  { v: 'v1.58.0', date: '2026-06-14', time: '15:05 EDT', body: "New content — a 14th Mayhem wave modifier: 💉 Adrenaline. When it rolls on a Mayhem (or Daily Challenge) wave, every enemy gets a desperate second wind: the more health it loses, the faster it moves, sprinting at up to +50% speed as it nears death. It's the wave-wide cousin of the Berserker boss, but on a fresh axis no other modifier touches — speed tied to damage taken, across the whole pack at once (Frenzy, by contrast, is just a flat speed bump). The catch it creates: chipping enemies down without finishing them is dangerous, because a wounded-but-alive enemy will race for the exit and leak before your towers can land the killing blow — so it rewards bursty, focused fire over thin, scattered damage. Because the speed-up ramps up from zero with missing HP, the average enemy is actually slower over its lifetime than under Frenzy, so it's challenging but fair. A faint red ring fades in around each accelerating enemy so you can see who's racing. Freeze and Frost slows still work normally (a frozen enemy doesn't move at all, so freezing counters it cleanly). Mayhem-only, pure run-time behaviour — no effect on your saves, chips, gold, or any existing balance. (Mayhem modifier pool is now 14.)" },
  { v: 'v1.57.0', date: '2026-06-14', time: '13:20 EDT', body: "Quality-of-life — the bottom-left next-wave preview now shows a ⚔ threat number: the total incoming health of the wave that's about to spawn (e.g. '⚔ 15.1k HP'). The little roster of enemy icons already told you what's coming and how many; the threat number tells you how hard it hits, all in one glance — so you can spot a nasty spike (a boss wave, or a wave thick with tanks) and buy up before it lands instead of getting caught short. It reddens on every fifth (boss) wave to flag the climactic ones, and it automatically reflects your difficulty and campaign level (a Hard or deep-campaign wave reads a bigger number). It's a planning estimate of the base wave — in Mayhem the per-wave chaos modifiers (swarm, titans, etc.) aren't baked in since they're rolled when the wave starts. Purely a display of numbers the game already computes — no effect on gameplay, balance, your saves, chips or gold." },
  { v: 'v1.56.0', date: '2026-06-14', time: '11:45 EDT', body: "New content — an eighth boss archetype: ⬜ the Juggernaut. From wave 20 onward the every-5th-wave boss carries one of the special mechanics (there were seven — self-Regen, Summoner, the damage-soaking Bulwark, the haste-spreading Enrager, the blinking Teleporter, the accelerating Berserker, and the tower-jamming Disruptor — and now there are eight). The Juggernaut is unstoppable: it's completely immune to crowd control, so the Time Freeze ability and Frost towers can't slow it or lock it down at all — it just keeps grinding forward at its steady boss pace (a steel-grey aura ring and an UNSTOPPABLE label on its health bar mark it out). Every other boss can be frozen to buy time; this one can't, so a build that leans on freeze/frost to handle bosses suddenly needs real damage to bring it down. It's a fresh kind of pressure — none of the other archetypes touch crowd control — and it doubles as a gentle check on the long-standing freeze/frost snowball. It still moves slower than a basic enemy and has no other tricks, so it's bounded and beatable; just point your damage at it. Like the other archetypes it only appears on deep (wave 20+) bosses — early/tutorial bosses are unchanged — and it's pure run-time behaviour, so there's no effect on your saves, gold, chips, or any existing balance. The cycle now runs Regen → Summoner → Bulwark → Enrager → Teleporter → Berserker → Disruptor → Juggernaut (so wave 55's boss is a Juggernaut, wave 60 wraps back to Regen). Hardens the late game through behaviour, not raw HP." },
  { v: 'v1.55.1', date: '2026-06-14', time: '09:30 EDT', body: "🩺 Health check — a periodic maintenance pass with no new feature, just a top-to-bottom check that the game is still healthy and the design notes still match the code. Good news this round: nothing was broken. The full automated test suite passes clean (669 checks across 69 groups, zero failures); the game still loads and plays by double-clicking the file offline (classic script tags in dependency order, no modules, inline favicon, no build step, all relative paths — and the installable-app service worker stays off for local-file play, so double-click play is untouched); and the version number, the offline-cache version and these notes are all in sync (v1.55.1). All seven game files are comfortably under the size guideline (the biggest is ~910 lines). Verified the counts in the design notes still match the game — 8 towers, 21 talents, 13 Mayhem wave modifiers, 15 achievements, 7 boss archetypes, 5 targeting modes — the boss HP slope (×0.6/wave), the Tesla Superconductor falloff (0.8), and the save loader's old/minimal-save migration all check out. Only housekeeping: refreshed the backlog's stale test-file counts (now ~4,234 lines / 69 groups). No drift or bugs found. Just a patch bump to record the checkup." },
  { v: 'v1.55.0', date: '2026-06-14', time: '23:55 EDT', body: "Balance — the Tesla's ⚡ Superconductor specialization got a buff so it's finally worth choosing. Tesla towers fire a lightning bolt that arcs from enemy to enemy, getting weaker with each jump. The level-5 choice is between Superconductor (chains to 5 enemies instead of 3) and Overcharge (only 3 jumps, but each does full damage). The problem: Superconductor's two extra jumps did so little damage (about a third, then a quarter) that they were basically wasted — Overcharge out-damaged it in almost every situation, so it was a trap pick. Now Superconductor's damage drops off more gently between jumps, so those extra targets take real damage. The result is a genuine choice: Superconductor is the swarm-clearer (against a full pack of 5+ chained enemies it now out-totals Overcharge), while Overcharge stays the pick for hitting a few tough targets hard (full damage to each of its 3). Base Tesla towers and Overcharge are completely unchanged. The buff is modest (about +21% total output at a full 5-enemy chain, within the per-run balance cap). No effect on your saves, chips or gold." },
  { v: 'v1.54.0', date: '2026-06-14', time: '23:05 EDT', body: "New map — ⚔️ Gauntlet! A fourth hand-crafted quick-play map joins Classic, Spiral and Serpent (Mayhem still rolls a fresh random path). Where the others wind, coil and switchback across the open board, the Gauntlet funnels every enemy through a dense central kill-box: it enters mid-left, then switchbacks tightly down the middle as a stack of closely-spaced vertical runs before exiting mid-right. Because those runs sit so close together, a single tower wedged between two of them can rake both at once — so it rewards a concentrated wall of fire over spreading thin, and splash/AoE towers (Cannon, Mortar, Tesla) absolutely feast. The path is long enough to give your towers plenty of firing time without trivialising the run. It comes with its own brand-new visual identity, a deep blood-red 'Crimson' theme (the campaign palette pool can roll it too now). Pick it from the MAP selector on the start screen; it tracks its own best-wave records per difficulty just like the other maps. Purely additive — no effect on your saves, chips, gold or balance; old saves load fine and the new map simply starts with no records yet." },
  { v: 'v1.53.0', date: '2026-06-14', time: '21:30 EDT', body: "New achievement — 🧰 Full Arsenal! Win a run with all eight tower types in play at once (Gun, Sniper, Frost, Cannon, Tesla, Poison, Mortar and a Booster all on the board when you win). It's a build-diversity challenge that completes the trio with 🧩 Specialist (win with one tower type) and ⚖️ Minimalist (win with five or fewer towers): instead of funneling all your gold into one carry tower, you have to field one of everything — spreading thin enough to keep at least one of each kind alive to victory. The achievement roster is now 15 badges. Purely additive — no effect on your saves, chips, gold, or balance; old saves load fine and the new badge just starts locked." },
  { v: 'v1.52.0', date: '2026-06-14', time: '20:10 EDT', body: "New content — a seventh boss archetype: 🔵 the Disruptor. From wave 20 onward the every-5th-wave boss carries a special mechanic (the cycle was six — self-Regen, Summoner, the damage-soaking Bulwark, the haste-spreading Enrager, the blinking Teleporter, and the accelerating Berserker — and now there are seven). The Disruptor jams your towers: every few seconds as it advances it fires an EMP pulse that knocks the nearest firing tower offline for a couple of seconds (a cyan crackle ring + ⚡ over the silenced tower, exactly like the Static Storm Mayhem modifier). Because it always hits whatever tower is closest, a dead zone in your coverage roams right along with the boss — so a Disruptor punishes leaning on one big tower at a chokepoint and rewards redundant, overlapping fire. It only ever silences one tower at a time so it stays bounded, your support/booster towers are immune, and freezing the boss pauses its pulses entirely (the silenced tower also always recovers on its own, even if the boss dies mid-pulse). Like the other archetypes it only appears on deep (wave 20+) bosses — early/tutorial bosses are unchanged — and it's pure run-time behaviour, so there's no effect on your saves, gold, chips, or any existing balance. The cycle now runs Regen → Summoner → Bulwark → Enrager → Teleporter → Berserker → Disruptor (so wave 50's boss is a Disruptor, wave 55 wraps back to Regen). Hardens the late game by pressuring your tower coverage rather than just stacking on more health." },
  { v: 'v1.51.0', date: '2026-06-14', time: '18:05 EDT', body: "New content — a 13th Mayhem wave modifier: 💠 Warden Surge. When it rolls on a Mayhem (or Daily Challenge) wave, a chunk of the basic enemies are swapped out for ◈ Warden escorts — the blue support enemies that project a shield bubble making everything near them take 40% less damage. With several wardens woven through the wave, almost the whole pack is shielded at once, so just pouring fire into the crowd barely scratches it. The play is target priority: pop the wardens to pop the bubble and the cluster instantly becomes vulnerable again. The new 🛡 Support targeting mode (set a tower to hunt healers/wardens first) and splash damage both shine here. Wardens never shield themselves or each other, so they're always killable. It's a Mayhem-only twist that raises the challenge through smart targeting rather than just bigger health bars, and it's pure run-time behaviour — no effect on your saves, chips, gold, or any existing balance. (Mayhem modifier pool is now 13.)" },
  { v: 'v1.50.1', date: '2026-06-14', time: '03:12 EDT', body: "🩺 Health check — a periodic maintenance pass with no new feature, just a top-to-bottom check that the game is still healthy and the design notes still match the code. Good news this round: nothing was broken. The full automated test suite passes clean (632 checks across 67 groups, zero failures); the game still loads and plays by double-clicking the file offline (classic script tags in dependency order, no modules, inline favicon, no build step, all relative paths — and the installable-app service worker stays off for local-file play, so double-click play is untouched); and the version number, the offline-cache version and these notes are all in sync (v1.50.1). All seven game files are comfortably under the size guideline (the biggest is ~880 lines). Verified the counts in the design notes still match the game — 8 towers, 21 talents, 12 Mayhem wave modifiers, 14 achievements, 6 boss archetypes, 5 targeting modes, and the save loader still cleanly upgrades old/minimal saves. Only housekeeping: refreshed the backlog's stale test-file counts (now ~3,991 lines / 67 groups). No drift or bugs found. Just a patch bump to record the checkup." },
  { v: 'v1.50.0', date: '2026-06-14', time: '16:40 EDT', body: "New content — a sixth boss archetype: 🔴 the Berserker. From wave 20 onward, the every-5th-wave boss carries one of the special mechanics (the cycle was five — self-Regen, Summoner, the damage-soaking Bulwark, the haste-spreading Enrager, and the blinking Teleporter — and now there are six). The Berserker starts at its normal slow boss pace, but the more you hurt it the faster it goes, accelerating up to +60% speed as it nears death — its crimson aura ring flares brighter and thicker as it rages, and it roars once it's wounded. So a Berserker you can't burst down quickly turns into a sprint for the exit right when it's almost dead, pressuring your damage and timing rather than just having more health. Counters: freezing it stops it cold (a frozen Berserker doesn't move, raging or not), and Frost slows blunt the rush; the play is to stack enough focused damage to finish it before the rage really kicks in. Even fully enraged it's still slower than a basic enemy, so it's bounded and beatable. Like the other archetypes it only appears on deep (wave 20+) bosses — early/tutorial bosses are unchanged — and it's pure run-time behaviour, so there's no effect on your saves, gold, chips, or any existing balance. The cycle now runs Regen → Summoner → Bulwark → Enrager → Teleporter → Berserker (so wave 45's boss is a Berserker, wave 50 wraps back to Regen). Hardens the late game through behaviour, not raw HP." },
  { v: 'v1.49.0', date: '2026-06-14', time: '15:30 EDT', body: "New targeting mode — 🛡 Support! Tap a tower and cycle its targeting (⏩ First / ⏪ Last / 💪 Strong / 📍 Close) one more step to the new 🛡 Support mode. A tower set to Support hunts the enemies that buff the rest of the pack — the 💚 healers (which heal everything nearby) and the ◈ wardens (which shield everything nearby in a 40%-damage-reduction bubble) — and shoots those first, before any normal enemy in range. Kill the support enemy and its whole cluster instantly loses the heal/shield, so a single Support-mode tower parked near a chokepoint can crack open packs that used to shrug off your fire. When there's no support enemy in range it just behaves like First (targets whatever's furthest along), so it's never a wasted setting. Pure new option — no effect on your saves, chips, gold or balance; old saves load fine and any tower keeps its current targeting." },
  { v: 'v1.48.0', date: '2026-06-14', time: '14:20 EDT', body: "New legendary perk — 🎲 Wildcard! It's a gamble: pick it from a draft and it instantly resolves into a random legendary perk for the rest of the run. You'll see exactly what you rolled (e.g. 🎲 → 💎 Diamond Core!) and that's the perk that goes into your run. It prefers legendaries you don't already have, and if you've somehow collected them all it falls back to another perk so it's never wasted. Because you'd be picking a legendary anyway, it doesn't make runs any stronger on average — it's pure surprise and replay variety, and like a few other perks it can show up again later. No effect on your saves, chips, gold, or balance." },
  { v: 'v1.47.0', date: '2026-06-13', time: '23:55 EDT', body: "Daily Challenge polish — the 🗓 Daily Challenge button now previews today's run before you commit. It shows the day's difficulty (Normal or Hard) and the icons of the modifiers you'll face today (💨🛡️⚡…), with the full modifier names spelled out in the hover tooltip, so you can size up the challenge at a glance. Everyone playing today still gets the exact same seeded run — this just surfaces what was already fixed by the date. There's also a new achievement to chase: 📆 Streak Keeper, unlocked by reaching a 7-day Daily Challenge streak (finish a daily on seven calendar days in a row). Your existing streak counts toward it. Both additions are purely informational/progression — no effect on saves, chips, gold, or balance." },
  { v: 'v1.46.0', date: '2026-06-13', time: '22:45 EDT', body: "Mobile polish — bigger, easier-to-tap buttons on phones. On a small portrait screen the shop tower buttons, the wave-control buttons (Start Wave, etc.) and the start-screen MODE/MAP/DIFFICULTY option buttons now grow to a comfortable finger-sized height (~44–46px, the standard recommended touch-target size) instead of the cramped ~30px they were before, so you're far less likely to fat-finger the wrong one. The floating upgrade/sell panel that pops up when you tap a tower got the same treatment — its Upgrade / Sell / targeting / spec buttons are now chunky enough to hit reliably mid-battle. It's a phone-only change: the enlargements are scoped to small screens (and the shop/control bump is portrait-only, so the deliberately-compacted landscape layout that keeps Start Wave on-screen is left exactly as it was), and desktop is completely untouched. Pure layout/CSS — no effect on your saves, chips, gold, or balance. This closes the last item on the 'polished-browser-game basics' checklist." },
  { v: 'v1.45.1', date: '2026-06-13', time: '21:30 EDT', body: "🩺 Health check — a periodic maintenance pass with no new feature, just a top-to-bottom check that the game is still healthy and the design notes still match the code. This round found and fixed one real save-robustness bug: a very old or hand-trimmed save that stored your chips but no talents list could crash the game on load (the loader assumed the talents list was always present). It now defaults a missing talents list cleanly, so any old save loads safely — your chips, achievements and stats all come through. Beyond that: the full automated test suite passes clean (597 checks across 64 groups, zero failures, two of them brand-new for this exact old-save case); the game still loads and plays by double-clicking the file offline (classic script tags in dependency order, no modules, inline favicon, no build step, all relative paths — and the installable-app service worker stays off for local-file play, so double-click play is untouched); and the version number, the offline-cache version and these notes are all in sync (v1.45.1). Verified the counts in the design notes still match the game — 8 towers, 21 talents, 12 Mayhem wave modifiers, 13 achievements, 5 boss archetypes, booster aura range 45, boss HP slope ×0.6/wave. No other drift found. Also refreshed the backlog's stale test-file counts (now ~3,750 lines / 64 groups) and confirmed the only remaining 'table-stakes' gap is chunkier tap targets on small phones. Just a patch bump to record the checkup." },
  { v: 'v1.45.0', date: '2026-06-13', time: '20:30 EDT', body: "Menu polish — the top of the start screen got a cleaner header. The title, version and tagline are now grouped into one tidy 'hero' block topped off with a soft blue accent line, instead of a loose stack where the little version number floated awkwardly between the tagline and the setup card. The ⚡ CIRCUIT DEFENSE title is a touch bigger with a richer glow, and the version now reads as a small rounded badge tucked right under the title (still click it to open these notes). Purely visual — nothing changes about how the menu works, your saves, chips, or balance, and it stays readable on phones. (Fourth slice of the ongoing 'revamp the starting menu' request — after the two-tier buttons, the animated PLAY button, and the grouped MODE/MAP/DIFFICULTY card.)" },
  { v: 'v1.44.0', date: '2026-06-13', time: '19:45 EDT', body: "Polish — the ✨ What's New panel now tells you what's actually new. When an update ships that you haven't read yet, those entries are highlighted at the top of the list with a gold NEW tag and a brighter accent stripe, so you can spot the fresh notes at a glance instead of trying to remember where you left off. The start screen flags it too: the ✨ What's New button shows a little gold count of how many updates are new since you last looked, and the version tag gets a small dot. Open the panel and everything is marked read — the count clears and the highlights fade on your next visit. The list also jumps back to the top each time you open it (newest first), so the latest change is always the first thing you see. Existing players and brand-new ones start 'caught up' (no wall of NEW tags on the whole back-catalogue) — only updates released from here on light up. Purely a UI nicety — no effect on gameplay, your saves, chips, or balance." },
  { v: 'v1.43.0', date: '2026-06-13', time: '18:30 EDT', body: "New feature — 🎮 gamepad support! You can now play with a controller. Plug in (or wake up) any standard Xbox-style pad, press a button, and a crosshair appears on the board — that's your cursor. Move it with the left stick or the D-pad. The buttons map like this: A places the selected tower (or, with no tower picked, selects the tower you're hovering — and it also aims the meteor when the meteor is armed); B cancels (deselects / un-arms); X cycles to the next tower you can afford; the bumpers and left trigger fire your three abilities (LB = Meteor, RB = Freeze, LT = Gold Rush); Start begins or stacks a wave; and Back pauses (Back or Start un-pauses). It's pure extra input sitting alongside mouse, touch and keyboard — nothing changes if you don't have a controller, and it has no effect on your saves, chips, gold or balance. (When no controller is connected the game behaves exactly as before.)" },
  { v: 'v1.42.0', date: '2026-06-13', time: '17:40 EDT', body: "Menu polish — the start screen's three setup choices (MODE, MAP and DIFFICULTY) are now grouped together inside one tidy bordered card, instead of sitting as three rows of floating labels and buttons drifting in the middle of the screen. The labels and their option buttons line up neatly on the left edge of the card, so the menu reads like a clean 'set up your run' panel — pick your mode, pick your map, pick your difficulty — rather than a loose pile of controls. Everything still works exactly as before: the same modes, maps, levels and difficulties, the same selections, no change to your saves, chips, or balance. It also shrinks and stays readable on phones. (Third slice of the ongoing 'revamp the starting menu' request — after the two-tier button layout and the animated PLAY button.)" },
  { v: 'v1.41.0', date: '2026-06-13', time: '16:12 EDT', body: "Menu polish — the start screen's ▶ PLAY button now has a little life to it. While you're sitting on the menu (where everything else is dimmed down), PLAY gently breathes a soft green glow and a thin band of light sweeps across it every few seconds, so your eye is drawn straight to the one thing you came to press. Purely cosmetic — the button does exactly what it always did, and nothing about your saves, chips, or balance changes. It also respects your system's 'reduce motion' setting: turn that on and the glow and glint are switched off entirely. (Another small slice of the ongoing 'revamp the starting menu' polish.)" },
  { v: 'v1.40.1', date: '2026-06-13', time: '23:59 EDT', body: "🩺 Health check — a periodic maintenance pass with no new feature, just a top-to-bottom check that the game is still healthy and the design notes still match the code. This round: the full automated test suite passed clean (543 checks across 58 groups, zero failures); the game still loads and plays by double-clicking the file offline (classic script tags in dependency order, no ES modules, inline favicon, no build step, all paths relative — and the installable-app service worker stays disabled for local-file play, so double-click play is untouched); old saves from before recent features still load via the migration defaults (talents/achievements/stats and the perk-state merge all default cleanly); and the save-on-quit write is wrapped so a full storage quota can't crash a run. Verified the version number, the offline-cache version and the in-game changelog are all in sync (v1.40.1), and that the counts in the design notes still match the game — 8 towers, 21 talents, 12 Mayhem wave modifiers, 13 achievements, 5 boss archetypes (Regen → Summoner → Bulwark → Enrager → Teleporter), booster aura range 45, boss HP slope ×0.6/wave. No drift found, nothing to fix. Refreshed the backlog's stale test-file counts (now ~3,400 lines / 58 groups) and re-noted the open table-stakes items (gamepad support, chunkier phone buttons). Just a patch bump to record the checkup." },
  { v: 'v1.40.0', date: '2026-06-13', time: '23:59 EDT', body: "New content — a fifth boss archetype: 🟣 the Teleporter. From wave 20 onward, the every-5th-wave boss carries one of the special mechanics (it used to cycle through four — self-Regen, Summoner, the damage-soaking Bulwark, and the haste-spreading Enrager — and now there are five). The Teleporter blinks ~80px forward along the path every few seconds and goes briefly intangible mid-jump (it fades out and can't be targeted or damaged for that split second, marked by a violet flash and a violet aura ring). Because it keeps skipping ahead, it spends less time in your towers' firing arcs — so it's harder to whittle down AND it reaches the exit sooner, pressuring your damage and timing rather than just having more health. Counters: freezing the boss pauses its blink entirely (a frozen Teleporter can't jump), and dense, overlapping coverage along the back stretch makes the most of the shrinking damage window. Like the other archetypes it only appears on deep (wave 20+) bosses — early/tutorial bosses are unchanged — and it's pure run-time behaviour, so there's no effect on your saves, gold, chips, or any existing balance. The cycle now runs Regen → Summoner → Bulwark → Enrager → Teleporter (so wave 40's boss is a Teleporter, wave 45 wraps back to Regen). Hardens the late game through behaviour, not raw HP." },
  { v: 'v1.39.1', date: '2026-06-13', time: '23:59 EDT', body: "Menu polish — the start screen's button row was getting clunky: ten equally-large buttons crammed into one line, so 'Talents', 'Records', 'Settings' and the rest were just as big and loud as the PLAY button you actually came to press. That row is now split into a clear two-tier layout. Up top, a prominent primary row holds the actions that LAUNCH a game — a big ▶ PLAY button, ⏯ Resume (when you have a run to continue), and 🗓 Daily Challenge. Below it, the menu/utility buttons (🧬 Talents, 🏅 Achievements, 🏆 Records, ✨ What's New, ⚙ Settings, 🗑 Reset All) sit in their own smaller, slightly muted toolbar, so they read as 'extras' you can dip into rather than competing with the main play button. Everything still does exactly what it did — this is purely visual hierarchy, no change to any button's behaviour, your saves, chips, or anything else. (First slice of the larger 'revamp the starting menu' request — the bottom-row buttons no longer dwarf everything else.)" },
  { v: 'v1.39.0', date: '2026-06-13', time: '23:59 EDT', body: "New content — a twelfth Mayhem wave modifier: 🏜️ Bounty Drought. When it rolls on a wave, every enemy in that wave (the boss included) pays out only HALF its usual gold. It's the mirror image of the existing 💰 Gold Rush, and the first wave twist that squeezes your economy DOWN instead of just scaling enemy stats — every other modifier so far either toughens enemies or hands you MORE gold. A drought wave starves you of the income you'd normally bank toward your next tower or upgrade, so it pressures your build on a fresh axis: you can't simply farm your way out of trouble, and a poorly-timed drought right before a boss can leave you short on firepower. It rewards spending wisely and keeping a reserve. Like every Mayhem twist it's per-wave and Mayhem-only — it never touches Classic or Campaign play, your saves, or any permanent progress (chips are still awarded normally at the end of the run; this only affects the in-run gold from kills during the drought wave). It also joins the rotation in the seeded Daily Challenge, so everyone faces it on the same day." },
  { v: 'v1.38.1', date: '2026-06-13', time: '23:59 EDT', body: "Bug fixes — two issues you reported. (1) Finishing a run no longer leaves a stale 'Resume' offer: completing a Campaign level (or winning a Quick run) now clears the saved game, so you can't keep resuming and re-winning the same level over and over. The Daily Challenge still leaves your normal saved game untouched, and 'Continue Endless' after a victory still resumes correctly. (2) Clicking to select a tower no longer makes it flicker: when you had a tower type picked from the shop and moved the cursor over an existing tower to select it, the red 'can't build here' placement preview was drawing right on top of that tower and flickering as it snapped between grid cells. The placement preview is now hidden whenever the cursor is over a tower you can click — so selecting a tower is clean. No effect on your saves, chips, or balance." },
  { v: 'v1.38.0', date: '2026-06-13', time: '23:55 EDT', body: "Balance — a talent-economy rework, straight from your feedback that talents are powerful (good!) but come way too cheap, so after just a few runs you're strong enough that the game stops being a challenge. The fix keeps every talent and all their power — it just makes them cost more to unlock, so building your dream loadout is the satisfying grind it's meant to be instead of a couple of evenings. Every talent's price went up (the general ~25% bump you suggested), and the real damage/power talents got hit harder: ⚔️ Firepower (your global +damage) and 🔬 Crit Lab now cost roughly double per rank, the eight 🛡 Tower Mastery talents (the cheap +30%-damage-per-tower-type ones) are doubled in cost, and 🌟 Overdrive (raises the tower level cap) is up 50%. In round numbers, maxing Firepower went from 285 to 515 chips, maxing one tower's Mastery from 60 to 120, and fully maxing the entire tree from ~2,350 to ~3,550 chips — about a 50% longer climb overall, with the steepest increases on exactly the upgrades that were trivialising the early game. Nothing was removed: every talent maps to a distinct mechanic, and deleting one would silently wipe chips you'd already spent on it. Your existing talents, ranks, chips and saves are all untouched — only the price of the NEXT rank changed. (If you've already maxed things out, a respec now refunds at the new higher prices, a small one-time bonus.)" },
  { v: 'v1.37.1', date: '2026-06-13', time: '23:30 EDT', body: "🩺 Health check — a periodic maintenance pass with no new feature, just a top-to-bottom check that the game is still healthy and the docs match the code. This round: the full automated test suite passed clean (505 checks, zero failures); the game still loads and plays by double-clicking the file offline (no module/network dependencies); old saves from before recent features still load correctly via the migration defaults; and a quick play-through plus a phone-sized layout check came back clean (no errors, no off-screen menus). Verified the version number, the offline-cache version and the in-game changelog are all in sync, and that the achievement/wave-modifier/boss/tower/talent counts in the design notes still match what's actually in the game (they do). No drift found, nothing to fix — the backlog's open items (gamepad support, chunkier phone buttons, a forking 'crossroads' map) are unchanged for a future update. Just a patch bump to record the checkup." },
  { v: 'v1.37.0', date: '2026-06-13', time: '22:10 EDT', body: "New content — an eleventh Mayhem wave modifier: ⚡ Static Storm. When it rolls on a wave, an electrical storm periodically knocks one of your firing towers offline for a couple of seconds — every few seconds a random tower gets zapped (a flickering ⚡ and a dark ring mark the one that's down), then it comes right back online and the storm moves on to another. So at any moment a different gap is opening somewhere in your defense, which rewards spreading coverage and overlapping fields of fire instead of leaning on one or two key towers. It pressures your defense on a fresh axis — tower uptime — rather than just piling on more enemy health, a continued nudge at the long-standing 'too easy' feedback. Support (booster) towers are immune — they keep buffing through the storm — and the effect is purely momentary: a knocked-out tower always recovers on its own. Like every Mayhem twist it's per-wave and Mayhem-only, so it never touches Classic or Campaign play, your saves, gold, or the economy (and it joins the rotation in the seeded Daily Challenge too)." },
  { v: 'v1.36.0', date: '2026-06-13', time: '20:30 EDT', body: "Polish — bosses now tell you what they do. From wave 20 onward each boss carries one of four special mechanics (self-Regenerate, Summoner, the damage-soaking Bulwark shield, or the haste-spreading Enrager). Until now the only hint was a coloured aura ring around the boss — easy to miss and impossible to decode mid-fight. The boss health bar at the top of the screen now shows the mechanic's NAME right under 'OVERLORD — WAVE N', colour-matched to the aura: green REGENERATING, red SUMMONER, blue BULWARK, orange ENRAGED. The Bulwark label even flips to SHIELDED for the couple of seconds its damage-soak shield is actually up, so you can see at a glance when to hold your big hits (or keep firing) instead of guessing from the ring's brightness. Early/tutorial bosses (waves 5/10/15 and the campaign level 1–5 finals) have no archetype, so their bar stays as before. Purely a readability/UI improvement — no change to boss behaviour, difficulty, your saves, gold, or anything else." },
  { v: 'v1.35.0', date: '2026-06-13', time: '19:25 EDT', body: "New enemy — the ◈ Warden, a support unit that turns up from wave 15 onward in every mode (Classic, Campaign and Mayhem). It doesn't hit hard or move fast; instead it projects a soft blue protective aura, and every enemy inside that bubble takes 40% LESS damage from your towers for as long as it stays close. A faint blue ring marks who's currently shielded, and the aura disc shows the Warden's reach. The counterplay is the whole point: focus the Warden down first — or splash it with area damage — and the moment it dies the protection on its whole cluster instantly drops. Leave it alive and even a modest pack becomes a slog, so it rewards target priority and AoE and quietly raises the skill floor without just piling on more health (a nudge at the long-standing 'too easy' feedback, on a fresh axis). Wardens give a generous bounty to reward popping them. Counters that bypass or break the shield: freezing a Warden pauses its aura entirely (a frozen Warden protects no one), and Frost slows keep it bunched for your AoE. Wardens never shield themselves or each other, so they're always killable. Pure run-time behavior — no effect on your saves, gold, chips, or any existing balance." },
  { v: 'v1.34.0', date: '2026-06-13', time: '18:05 EDT', body: "New content — a fourth boss archetype: 😡 the Enrager. From wave 20 onward, the every-5th-wave boss carries a special mechanic (it used to cycle through three — self-Regen, Summoner, and the damage-soaking Bulwark shield — and now there are four). The Enrager projects a haste aura: every enemy near it moves 35% faster, marked by a faint orange ring, and the boss itself glows orange so you can spot it coming. A pack escorted by an Enrager rushes your towers and reaches the exit sooner, so it pressures your damage and timing without simply adding more health — and a fast escort can overwhelm a defense that was comfortable a moment ago. Counters: freezing the boss pauses its aura entirely (a frozen Enrager can't speed anyone up), and Frost slows still apply on top of the haste, so crowd-control answers it directly. Like the other archetypes it only appears on deep (wave 20+) bosses — early/tutorial bosses are unchanged — and it's pure run-time behavior, so there's no effect on your saves, gold, or the rest of the game. Hardens the late game through behavior rather than raw HP." },
  { v: 'v1.33.0', date: '2026-06-13', time: '16:40 EDT', body: "New content — a tenth Mayhem wave modifier: 💚 Regeneration. When it rolls on a wave, every enemy in that wave (the boss included) slowly heals itself — 2% of its maximum health per second — for as long as it's alive on the path. A small green halo marks the regenerating enemies so you can see who's healing. It won't matter if your towers are already shredding the wave, but if your damage is marginal those stragglers will keep patching themselves up and start leaking through — so it rewards burst and sustained DPS and punishes an under-built defense, without simply piling on more raw health. Counters: freezing an enemy pauses its regen (Frost towers, the Freeze ability), and anything that bursts a target down fast beats the heal outright. Like all Mayhem twists it's per-wave and Mayhem-only — it never touches Classic or Campaign play, your saves, or the economy. (It also shows up in the seeded Daily Challenge's modifier rotation.)" },
  { v: 'v1.32.1', date: '2026-06-13', time: '15:30 EDT', body: "🩺 Health check (the every-6th-run maintenance pass — no new feature, just keeping things solid) plus one small fix. The full automated test suite is green (465 checks across 51 groups, zero failures) with zero console errors, the game still loads and plays by double-clicking the file (classic script tags in order, no ES modules, inline favicon, no build step, all paths relative — offline play intact), and old saves still migrate cleanly. Checked the maintainer docs against the actual code — every number still matches (8 towers, 21 talents, 9 Mayhem wave modifiers, 13 achievements, booster aura range 45, boss HP slope ×0.6/wave, Glass Cannon +50% dmg / −30% range). The fix: the installable-PWA's offline cache version was still stamped 'v1.30.0' even though the game had moved on to v1.32.0 — so a player who'd installed the hosted web-app could have kept getting the older cached version offline instead of the latest. Bumped it to match (v1.32.1) and added a test that fails if it ever falls out of sync again, so future updates can't silently ship a stale offline cache. This only affects the hosted/installed web-app; double-click-the-file play and your saves are completely unaffected. Remaining polish on the list: gamepad support and splitting the (dev-only) test file, now ~2900 lines." },
  { v: 'v1.32.0', date: '2026-06-13', time: '14:40 EDT', body: "New content — 🔮 Glass Cannon, a new legendary perk for the every-5-waves draft. It's a true high-risk / high-reward trade: ALL your towers hit 50% harder, but their firing range shrinks by 30%. That extra punch can melt tanks and bosses, but the shorter reach means each tower covers far less of the path, so you'll want to place them tightly along the action and lean on slows or chokepoints to keep enemies in range. Unlike most upgrades it's a genuine choice rather than a free win — the lost coverage is a real cost, so it rewards smart placement instead of just snowballing an already-comfortable run. (The range cut applies to attacking towers only; booster auras are unaffected, since boosters don't deal damage.) Save-safe and offline like everything else — it slots into the existing perk system, persists across save/resume, and has no effect on older saves, gold, chips, or your other progress." },
  { v: 'v1.31.0', date: '2026-06-13', time: '13:05 EDT', body: "New content — a 🔥 Daily streak! The Daily Challenge now rewards showing up every day. Each calendar day you finish today's daily run (win, lose, or play on into endless — any finish counts), your streak grows by one; miss a day and it resets. Your current streak appears right on the 🗓 Daily Challenge button (e.g. '🔥5d' once you're two days deep) and in the 🏆 Records panel, with a tooltip nudging you to play and keep it alive. Playing the daily more than once in a day won't pad the count — it's one per calendar day — and the streak is purely a 'keep your run going' loop: it has no effect on gameplay, difficulty, gold, chips, or any of your other progress. Like the rest of the Daily Challenge it's fully offline (the day is read from your device's local clock, no network), and it lives in its own new save field, so existing saves are untouched and simply start at zero. A natural follow-up to the v1.28.0 Daily Challenge for anyone who likes a reason to come back tomorrow." },
  { v: 'v1.30.0', date: '2026-06-13', time: '11:30 EDT', body: "Install it like an app — Circuit Defense is now a PWA (progressive web app). When you play the online (hosted) version, your browser will offer to install/add it to your home screen or desktop, after which it opens in its own clean window with no address bar — and, thanks to a small offline cache, it keeps working even with no connection. This is especially handy on phones: tap your browser's 'Add to Home Screen' and you get a proper app icon (the gold ⚡ bolt) that launches straight into the game. Under the hood this adds a web-app manifest, an app icon, and a service worker that caches the game's files on first visit so return visits load instantly and offline. Important: none of this changes the double-click-the-file experience — opening the game from a local file is still a pure, no-network, no-install static page (service workers simply don't apply there), and there's still no build step. No effect on gameplay, balance, or your saves — this is pure packaging/polish." },
  { v: 'v1.29.0', date: '2026-06-12', time: '23:30 EDT', body: "New content — four fresh achievement badges to chase (the trophy collection grows from 9 to 13)! 🕊️ Pacifist — win a game without ever casting an ability (no Meteor, Freeze, or Gold Rush): a pure-towers challenge. 🧩 Specialist — win using only ONE type of tower (an all-cannon or all-frost run, say), rewarding a committed mono-build. ⚖️ Minimalist — win with 5 or fewer towers placed, for the efficient defenders who'd rather upgrade than sprawl. 🗓️ Daily Devotee — reach wave 20 in the Daily Challenge, giving the new daily run something extra to play for. They all show up in the 🏅 Achievements panel and pop the usual unlock toast on the end screen. Save-safe and purely additive — no effect on balance, gold, or your existing progress; the new badges just start locked and unlock the first time you pull them off. (Two notes: the mono-tower and minimalist checks read your final board at the moment of victory, and Pacifist can only be earned on a run played start-to-finish — resuming a saved game can't verify you went ability-free earlier, just like the existing Flawless badge.)" },
  { v: 'v1.28.0', date: '2026-06-12', time: '22:30 EDT', body: "New mode — 🗓 Daily Challenge! A fresh button on the start screen launches today's seeded run: the map path, the difficulty, and the whole sequence of Mayhem wave-modifiers are all decided by today's date, so every player faces the exact SAME challenge today — a built-in way to compare scores day to day (and against yourself). It plays like a Mayhem run (animated 'world on fire' theme, wild per-wave twists) but with one key difference: the map is FIXED for the day — it never re-shuffles every 5 waves — so the run is fully comparable. The difficulty is locked to Normal or Hard by the seed (a daily is meant to be a test, never Easy). Your best wave for each day is tracked under its own record (shown on the Daily button and in the 🏆 Records panel), completely separate from your normal map records. A daily is a one-off: it isn't saved or resumable, and — importantly — starting one does NOT disturb your normal saved run, so you can hop into today's challenge and still Resume your campaign afterwards. Comes back fresh at local midnight. Offline-safe like everything else (the seed is derived from your device's date, no network). No effect on your saves, chips, or any existing balance." },
  { v: 'v1.27.1', date: '2026-06-12', time: '21:35 EDT', body: "🩺 Health check (the every-6th-run maintenance pass — no new feature this time, just making sure everything is still solid). The whole automated test suite passes (393 checks across 47 groups, zero failures) with zero console errors, and the game still loads and plays by double-clicking the file — classic script tags in the right order, no ES modules, inline favicon, no build step, all paths relative, so offline play is intact. Old saves still migrate cleanly (a minimal pre-update save loads via the additive defaults: achievements/stats, perk state, map theme). Checked the maintainer docs against the actual code — every number still matches: 8 towers, 21 talents, 9 Mayhem wave modifiers, booster aura range 45, the boss HP slope (×0.6/wave), and the enemy-HP curve. Versions are consistent everywhere (v1.27.1). All game source files stay well under the size cap (largest ~713 lines) with no dead code, leftover debug logging, or TODOs, and the online deploy is still a correct static copy of the raw files. Nothing to fix — logged that the dev-only test file is now the biggest file in the repo (2559 lines) and worth splitting soon, and that gamepad + installable-PWA support remain the next polish items." },
  { v: 'v1.27.0', date: '2026-06-12', time: '20:30 EDT', body: "New content — two fresh Mayhem wave modifiers! In Mayhem mode each wave can roll a random twist (Frenzy, Swarm, Titans, Power Surge, Fog, …). Two new ones join the pool: 🛡️ Armored Surge — every enemy in the wave, the boss included, gains a chunk of armor that soaks part of each hit, so your fast low-damage towers suddenly struggle; lean on the Mortar (its shells ignore armor entirely), Poison (corrodes armor on every tick) or the Sniper's armor-piercing path to punch through. 🔌 Brownout — a power dip that makes ALL your towers fire 25% slower for that wave, so the enemies you'd normally shred get more time to advance; bring extra firepower or a Booster to compensate. These round out the tower-stat twists (Power Surge boosts damage, Fog cuts range, and now Brownout cuts fire-rate) and add the first wave modifier that plays with enemy armor. Mayhem-only and per-wave — they never touch the normal/campaign modes, your saves, or the economy." },
  { v: 'v1.26.0', date: '2026-06-12', time: '19:30 EDT', body: "Balance — the Sniper's Executioner specialization gets a real reason to exist. At level 5 a Sniper picks one of two upgrades: Deadeye (20% chance to crit for ×4 damage) or Executioner (bonus damage vs tanks & bosses). The problem: Deadeye's crits work out to about +60% damage on average against EVERYTHING, while Executioner only gave +60% against tanks and bosses and nothing against regular enemies — so Deadeye matched it on the big targets and beat it everywhere else, making Executioner a trap pick. Executioner's bonus is now boosted from +60% to +90% vs tanks & bosses, turning it into the dedicated boss-killer: against the targets that actually matter it now out-damages Deadeye, with no crit-RNG (guaranteed every shot), which is exactly what you want for bursting down a boss before it leaks. Deadeye stays the consistent all-rounder (and still scales with crit talents/perks). With bosses recently getting tankier and gaining special mechanics, a true anti-boss spec finally has a home. No effect on saves, gold, or other towers." },
  { v: 'v1.25.0', date: '2026-06-12', time: '18:40 EDT', body: "New content — boss archetypes! Bosses (every 5th wave) used to be just big health bars. From wave 20 onward, each boss now also carries a special MECHANIC, cycling through three types so deep waves and late campaign levels stay interesting instead of melting to the same army that cleared wave 10. 🟢 Regenerator — slowly heals itself, so if your damage isn't keeping up it'll out-heal you and break through (freezing it pauses the healing). 🔵 Bulwark — periodically raises a shield that soaks 60% of incoming damage for a couple of seconds; its aura ring flares bright while the shield is up, so time your big hits (or just keep the pressure on) for when it drops. 🔴 Summoner — spawns waves of weak minions behind it, splitting your towers' attention and threatening extra leaks if you tunnel-vision the boss. A coloured aura around the boss tells you which kind you're facing, and a short ominous sound plays when a boss uses its power. This hardens the LATE game specifically — the early/tutorial bosses (waves 5/10/15 and the campaign level 1–5 finals) are completely unchanged — and it does so through behaviour rather than yet more health, which the regular difficulty curve is already maxed out on. No effect on your saves, gold, or any tower." },
  { v: 'v1.24.4', date: '2026-06-12', time: '17:25 EDT', body: "Balance: tougher late-game bosses (chipping away at the recurring 'game is too easy' feedback). Every 5th wave is a boss, and a boss's health is the normal enemy's health times a multiplier that grows each wave. That multiplier's per-wave growth is steepened from 0.5 to 0.6, so bosses get relatively tankier the deeper you go — about +3% health at wave 5, +5% at wave 10, +8% at wave 20, +10% at wave 30, up to a hard ceiling of +20% in extreme endless. Early waves are barely touched (the fix targets the documented mid-/late-game plateau, not the opening, which already feels right), and the change is bounded so no single number moves more than the project's per-run balance limit. Why bosses specifically: the regular enemy HP curve is already pushed to its design ceiling, so the boss multiplier is the open lever for making deep waves and late campaign levels demand a real, upgraded defense instead of coasting on an early-built army. No effect on your saves, gold, or any other tower/enemy." },
  { v: 'v1.24.3', date: '2026-06-12', time: '16:10 EDT', body: "Balance: final slice of your 'cut booster range in half' request — the Booster's aura radius drops from 52 to 45. That completes the full halving: across three small steps the base aura range has gone 90 → 68 → 52 → 45 (exactly −50% of where it started), so a single booster now covers only about a quarter of the area it originally did (45²/90²). One booster can no longer blanket a sprawling defense — you'll place it right beside your key towers, build a second for spread-out layouts, or take the Network spec (+50% range), which now matters a lot more off the smaller base. As always the Network spec and Booster Mastery talent widen the aura from this new base, and saves are unaffected — a resumed run's boosters just use the new radius. This closes out the booster-range feedback item." },
  { v: 'v1.24.2', date: '2026-06-12', time: '15:05 EDT', body: "🩺 Health check (every-6th-run maintenance pass — no new feature this time). Verified the whole game is still healthy: full automated test suite passing (356/0 across 43 test groups), zero console errors, and the game still loads and plays by double-clicking the file (classic script tags, inline favicon, no build step). Confirmed old saves still load — a save from before the achievements/stats system, and a minimal pre-update run save, both migrate cleanly and resume. Checked the project docs against the actual code: every formula and number in the maintainer notes still matches (8 towers, booster aura range 52, the enemy-HP curve, the perk rarity odds, 21 talents) — no drift. All game source files remain well under the size cap (largest ~676 lines), with no dead code, leftover debug logging, or stale references. The deploy that publishes the game online is still a correct static copy of the raw files. Nothing to fix — logged a couple of minor follow-ups (the dev-only test file is getting long; gamepad + installable-PWA support remain the next polish items) for future runs." },
  { v: 'v1.24.1', date: '2026-06-12', time: '14:05 EDT', body: "Balance: shrank the Booster's aura range again (second slice of your 'cut booster range in half' request). The booster buffs every tower inside a circle around it; this update drops that radius from 68 to 52 (about −24%, roughly −41% of the area it now covers). On top of the earlier 90→68 cut, a single booster's coverage is now well under half of what it was originally, so one booster can no longer blanket a whole sprawling defense — you'll place it deliberately near your key towers, build a second for spread-out layouts, or lean on the Network spec (+50% range) which matters more off the smaller base. As before, the Network spec and Booster Mastery talent still widen the aura from this new base. Kept to ~a quarter this run per the project's gradual-balance rule; one more small step (52→~45) finishes the full −50%. Saves are unaffected — resumed boosters just use the new radius." },
  { v: 'v1.24.0', date: '2026-06-12', time: '13:20 EDT', body: "Grid placement — line your towers up cleanly! When you go to place a tower, its spot now snaps to a tidy grid so rows and columns stay neat instead of scattered wherever the cursor happened to be. A faint grid of dots fades in while you're placing to show where the slots are, and the placement preview ring sits exactly where the tower will land. The grid is sized to the minimum tower spacing, so neighbouring slots are still buildable — you can pack a clean wall of towers. Prefer free-hand placement? There's a new ▦ Grid snap toggle in ⚙ Settings (default on) to switch it off. Purely a placement-feel change — no effect on damage, economy, or existing saves." },
  { v: 'v1.23.0', date: '2026-06-12', time: '12:15 EDT', body: "New tower — 🎇 Mortar! An eighth tower joins the shop (hotkey 8): a long-range, slow-firing siege piece that lobs an explosive shell which detonates in an area AND completely ignores enemy armor. That makes it a dedicated counter to the heavily-armored crowd — shield enemies, tanks and bosses — which normally shrug off a chunk of every hit; the Mortar's blast lands its full damage on them from clear across the board. The trade-off is a slow reload, so it's about heavy single shots rather than rapid fire, and against ordinary unarmored enemies a Cannon still out-damages it — it's a specialist, not an upgrade. At max level pick a specialization: Demolisher (+35% damage) for raw punch, or Saturation (+55% blast radius) to blanket a bigger group. There's also a new Mortar Mastery talent (+6% damage & +2% range per rank) so you can invest in it permanently like the other towers. No effect on existing saves — a resumed run that never built a Mortar plays exactly as before." },
  { v: 'v1.22.0', date: '2026-06-12', time: '12:30 EDT', body: "New legendary perk — 🩸 Last Stand. A comeback power-up that gets stronger the more lives you've lost in the run: ALL your towers deal +3% damage for every life that has leaked past your defenses, up to a maximum of +60% (reached at 20 lives lost). If you're cruising through a run without losing a single life it does nothing at all — it only kicks in when you're under pressure, turning a near-loss into a dramatic rally. Rolls in the every-5-waves upgrade draft at the rare legendary tier, alongside Diamond Core, Midas Touch and the rest. Designed deliberately so it can't make an already-easy run any easier (a flawless player gets zero benefit) — it's purely a rubber-band for when the boss waves start breaking through. No effect on saves; an in-progress run that picks it up keeps its life-loss tally." },
  { v: 'v1.21.0', date: '2026-06-12', time: '11:05 EDT', body: "Wave preview, upgraded: the between-waves 'Next:' line at the bottom-left of the board now shows the EXACT make-up of the wave you're about to start — a little coloured dot for each enemy kind with how many of them are coming (e.g. ● ×13, » ×3 fast, ◆ ×4 tanks, 🛡 shield, 👻 phantom, ☠ ×1 boss), instead of just listing the kinds by name. Now you can see at a glance whether the next wave is a tank-heavy push or has a boss, and buy/upgrade towers accordingly. The dots use each enemy's own colour and carry the same shape symbols the colourblind aid uses, so it's readable by shape too. Purely a display improvement — no effect on gameplay, balance or saves." },
  { v: 'v1.20.2', date: '2026-06-12', time: '09:15 EDT', body: "🩺 Health check (every-6th-update maintenance pass — no gameplay changes). Full test suite green (zero console errors), all eight code files comfortably within the size limit (largest ~637 lines vs the ~1500 cap), and every documented formula re-verified against the actual code (scoring, enemy-HP scaling, the economy trim, the booster aura power & range, the poison DoT) — all matched. Old saves confirmed to still load via the migration defaults (an old profile with no achievements/stats and an old run with no map-theme both loaded cleanly with full tower stats rebuilt), and double-click/offline play re-verified. Also fixed a flaky test: the economy-trim check measured the gold bank AFTER the random 5-/10-wave perk picks, so a gold perk could push it over the limit and fail by chance — it now checks the deterministic pre-draft economy instead, which is exactly what the trim affects. The remaining 'polished-browser-game' gaps still on the roadmap: gamepad support and an installable/offline web-app manifest (the game is already offline by double-click)." },
  { v: 'v1.20.1', date: '2026-06-12', time: '22:45 EDT', body: "Balance: shrank the Booster's aura range (your request to cut booster range in half). The booster buffs every tower inside a circle around it; that circle was quite large, so one booster could blanket most of your defenses — part of why a single gunner + booster could carry a run. This update is the first half of the cut: the base aura radius drops from 90 to 68 (about −24%, which is ~−43% of the area it covers), so a booster now reaches fewer towers and you'll want to place it more deliberately (or build a second one for spread-out defenses). The Network spec still widens it by +50% and the Booster Mastery talent still adds range, just from the smaller base. Kept to ~a quarter this run per the project's gradual-balance rule; the remaining reduction toward the full −50% will follow over the next couple of updates. Saves are unaffected — a resumed run's boosters simply use the new radius." },
  { v: 'v1.20.0', date: '2026-06-12', time: '21:30 EDT', body: "Accessibility: the mid-game upgrade picker (the 'Choose an upgrade' screen that pops up every 5 waves) is now keyboard-operable — the last menu in the game that was mouse-only. When it opens, your keyboard focus lands on the first perk card; Tab and Shift+Tab cycle through the three choices (and stay trapped inside the picker so you can't tab away to the paused board behind it); and Enter or Space picks the highlighted perk. The focused card lifts and shows a blue ring just like a mouse hover. Esc is intentionally still disabled here — you have to pick one. It's also tagged as a dialog for screen readers. Pure interface polish — no effect on gameplay, balance, the perks themselves or saves." },
  { v: 'v1.19.0', date: '2026-06-12', time: '06:13 EDT', body: "Accessibility: the start-screen menus (Talents, Achievements, Records, Settings, What's New) are now fully keyboard-navigable. Before, they could only be opened and closed with the mouse. Now: pressing Esc closes whichever panel is open; opening a panel moves your keyboard focus into it and Tab cycles through its buttons without escaping to the dimmed page behind; and closing a panel returns focus to the button you opened it from. Buttons and controls also show a clear blue focus ring when you're navigating by keyboard (it stays hidden for mouse clicks). Panels are tagged as dialogs for screen readers too. Pure interface polish — no effect on gameplay, balance or saves." },
  { v: 'v1.18.0', date: '2026-06-12', time: '19:40 EDT', body: "Accessibility: a new ♿ Colorblind aid toggle in ⚙ Settings. Most enemy types already show a symbol (+ heal, 🛡 shield, ✂ split, 👻 phantom, ☠ boss), but the fast and tank enemies were told apart by COLOUR alone (purple vs orange), which is hard if you're colourblind. Turn the aid on and every enemy kind gets its own symbol too — » for the quick ones, ◆ for the heavy tanks — so you can read the board by shape, not just hue. Off by default, saves on your device, and zero effect on gameplay or balance." },
  { v: 'v1.17.0', date: '2026-06-12', time: '18:15 EDT', body: "Sharper graphics on high-resolution screens (Retina, 4K, and Windows display scaling like 125%/150%). The game board was drawn at a fixed resolution and then stretched to fit your screen, so on a high-DPI display the towers, enemies and text looked a little soft. It now draws at your screen's true pixel density (up to 2×), so everything is crisp — while staying exactly the same size and playing identically. No effect on gameplay, balance, controls or saves; on a standard 1× display nothing changes at all." },
  { v: 'v1.16.4', date: '2026-06-12', time: '16:45 EDT', body: "🩺 Health check (every-6th-run maintenance pass — no gameplay changes). Full test suite green (272/0, zero console errors); all eight code files comfortably within the size limit (largest is ~656 lines vs the ~1500 cap); every documented formula re-verified against the actual code (scoring, enemy-HP scaling, the economy trim, the booster-aura taper, the touch radius) — all matched. Old saves confirmed to still load via the migration defaults (an old meta with no achievements/stats and an old run with no map-theme both loaded cleanly), and double-click/offline play re-verified. Tidied the docs: the project's root redirect page (index.html → tower-defense.html, used by the hosted version) is now documented. The remaining 'polished-browser-game' gaps — colourblind-safe palette, gamepad support, high-DPI crispness and menu keyboard navigation — are still on the roadmap for future updates." },
  { v: 'v1.16.3', date: '2026-06-12', time: '15:30 EDT', body: "Touch controls: tapping the board on a phone is now reliable. Two things were fighting you. First, the spot you tap to select a tower was sized for a mouse — on a phone the board is shrunk to fit, so an on-screen tower was only about a 7-pixel target, easy to miss. On touch devices the tap area around each tower is now much more forgiving (it still can't accidentally grab a tower when you meant to place a new one beside it). Second, the board now reacts the instant you press instead of waiting for the browser's tap-release (which some mobile browsers delay by a fraction of a second), so placing towers, aiming the meteor and opening the upgrade menu all feel snappier — on mouse and touch alike. The board also no longer scrolls or pinch-zooms the page out from under you while you're tapping on it. Desktop play is unchanged." },
  { v: 'v1.16.2', date: '2026-06-12', time: '14:05 EDT', body: "Balance: cooled the 'one maxed booster carries the whole run' problem (your campaign-6-on-hard note — beaten with a single gunner + a maxed booster). A booster's aura used to grow +10% damage per level (up to +75% at max); it now grows +8% per level instead. A low-level booster is completely unchanged — the trim only kicks in as you pour money into one, where a maxed booster now gives +65% instead of +75%, so a buffed tower does about 6% less at max. Small and deliberate (it shouldn't gut a real multi-tower build), just enough to make a single super-booster a bit less of an auto-win. A resumed run keeps the exact same booster power. More tower-power tuning to come if the solo-carry is still too strong." },
  { v: 'v1.16.1', date: '2026-06-12', time: '13:20 EDT', body: "Balance: trimmed the early gold snowball (your note that you can clear classic-normal on the money from just the first 10 rounds). Kills were paying ~70% of your early income, so per-kill bounty is now a touch lower — about 20% less on wave 1, fading to ~10% by wave 10 and barely anything in deep endless, so it bites where you over-build but doesn't starve long runs. The between-wave clear bonus was also cut ~20%. Net effect: your war chest after 10 clean waves drops ~13% (measured), so you can't quite afford a full army from the opening rounds. A modest, simulated step — more to come if it's still too easy." },
  { v: 'v1.16.0', date: '2026-06-11', time: '23:55 EDT', body: "The victory/defeat screen now has a SCORE and a letter grade (your request), and it's been restyled so it's no longer an overwhelming wall of text. Every run is scored on how far you got (waves + campaign depth), how clean it was (lives kept, big combos, and using FEWER towers), and how much gold you banked — all scaled by difficulty. You get a grade from F up to S (S = a flawless win with no lives lost), and the game tracks your all-time best score with a ★ celebration when you beat it. The old run-on summary is gone: now there's a big score + grade up top, a tidy stats grid (waves / kills / lives / gold / combo / towers), and your MVP towers, perks and any new achievements as their own clean lines." },
  { v: 'v1.15.0', date: '2026-06-11', time: '23:30 EDT', body: "Mobile deep-dive #2 (your request — 'when you start a game it's tiny' and 'What's New is shown behind the game'). Two fixes: (1) On phones & tablets the What's New rail no longer opens by default — it used to stack full-width BELOW the board and bury it, so now it starts collapsed on small screens and only appears if you tap ✨ What's New (your choice is remembered). (2) The board is a wide landscape shape, so holding the phone upright squeezes it small — there's now a proper LANDSCAPE layout: rotate your phone sideways and the board grows to fill the screen height (much bigger), with the top bar and buttons compacted to give it room. A '↻ Rotate for a bigger board' hint shows in portrait so you know. Desktop is unchanged." },
  { v: 'v1.14.1', date: '2026-06-11', time: '22:40 EDT', body: "🩺 Health check (every-6th-run maintenance pass): full test suite green (230/0, zero console errors), all code files comfortably within the size limit, every documented formula re-verified against the code, no dead code, and old saves confirmed to still load via the migration defaults. New this time — at your request, the health check now also verifies the game VISUALLY on both a large display and a phone, not just via tests: every menu was opened at 1280px and 390px and confirmed on-screen, scrollable and playable. That pass surfaced the concrete phone problems behind your 'tiny game / What's New behind the game' note (measured: the board shrinks to 374×233px and the What's New rail dumps full-width below the fold) — logged in detail for the next update to fix. No gameplay changes." },
  { v: 'v1.14.0', date: '2026-06-11', time: '21:30 EDT', body: "Phones & tablets are now properly supported (your request — it 'looked terrible on phones'). The menu, talents, achievements, records, settings and every-5-waves draft used to be crammed into the small scaled-down game board with no way to scroll or reach them, and rows of buttons ran off the screen. On narrow screens (≤920px, covering phones and iPad-size tablets) those panels now fill the whole screen and scroll, button rows wrap, and the talent/achievement grids reflow to 2 columns (1 on small phones) — no more sideways scrolling or cut-off content. The game board itself already scaled to fit. (First slice — start screen, all overlays and in-game chrome. Fine-tuning of in-game touch ergonomics can follow.)" },
  { v: 'v1.13.8', date: '2026-06-11', time: '20:08 EDT', body: "The maps no longer all look the same (your request). Each Classic-mode map now has its own colour theme — Classic stays the blue circuit, Spiral runs emerald green, Serpent glows warm amber. Campaign rolls a different (but calm) colour scheme each attempt, and Mayhem now burns: its palette sweeps through wild, fiery hues that shift as you play. Purely visual — no effect on gameplay, and a resumed run keeps the colours it started with." },
  { v: 'v1.13.7', date: '2026-06-11', time: '18:51 EDT', body: "What's New entries now show the TIME alongside the date (your request) — so when several updates land on the same day you can see the order at a glance. New entries are timestamped going forward; older entries (before this change) just show their date, since no time was recorded for them." },
  { v: 'v1.13.6', date: '2026-06-11', body: "A few fixes you asked for: the ✨ What's New button now also CLOSES the panel if it's already open (it toggles), and the ⚙ Settings button toggles the same way. And difficulty got rebalanced for fresh runs — Easy is now genuinely very easy (lots of gold & lives, much weaker enemies), and Normal is a little gentler too, so the early waves aren't a wall." },
  { v: 'v1.13.5', date: '2026-06-11', body: "What's New now shows the FULL update history again (your request) — the previous version had trimmed it to just the 10 most-recent entries, but you'd rather see everything. The panel scrolls, so the whole list is here to browse top to bottom." },
  { v: 'v1.13.4', date: '2026-06-11', body: "🩺 Health check (every-6th-run maintenance pass): full test suite green (200/0, zero console errors), all code files comfortably within size limits, every documented formula re-verified against the code, and old saves confirmed to still load via the migration defaults. Double-click play (file://) re-checked. No gameplay changes. Also tidied this What's New list back to its intended ~10 most-recent entries (the complete history is still in CHANGELOG.md), and refreshed the roadmap's table-stakes audit (touch controls remain the top mobile gap)." },
  { v: 'v1.13.3', date: '2026-06-11', body: "Difficulty curve steepened (your feedback — early waves are hard now but it plateaus). Enemy health now ramps faster the deeper you go: barely changed in the first ~10 waves (so the strong early game stays), then progressively tougher — roughly +12% by wave 10, +18% by wave 30, climbing toward +25% in deep endless. Each later wave is now a bigger jump than before." },
  { v: 'v1.13.2', date: '2026-06-11', body: "The ⚙ Settings panel now has a 🔊 Volume slider — set the master volume anywhere from 0 to 100% instead of just on/off mute. It scales all the game's sound and saves on your device. (Mute still works as a quick toggle.)" },
  { v: 'v1.13.1', date: '2026-06-11', body: "Hovering a tower in the shop now previews its range — a dashed ring (with the tower's name and range) appears on the board so you can compare coverage before you even pick it up. The shop tooltips show the range number too. (Once you select a tower, the range still follows your cursor as you place it, like before.)" },
  { v: 'v1.13.0', date: '2026-06-11', body: "New ⚙ Settings panel on the start screen. Toggle screen shake on/off, and set particle effects to Full / Reduced / Off — great for lower-end devices or if you just prefer a calmer board. Both save on your device. (These stack with your OS 'reduce motion' setting, which already minimises both.)" },
  { v: 'v1.12.2', date: '2026-06-11', body: "Cleaner game feel: when a bunch of enemies die together (splash, meteor, a fat combo), the floating +gold and CRIT numbers no longer pile up into an unreadable confetti — nearby ones now merge into a single growing number (e.g. +25 instead of +5 +7 +3 +10). Easier to read, less visual noise." },
  { v: 'v1.12.1', date: '2026-06-11', body: "The perk icons in the top-left of the board (the milestone bonuses you draft every 5 waves) now have a hover tooltip — mouse over any one to see its name and exactly what it does, colour-coded by rarity. No more forgetting which legendary you grabbed three waves ago." },
  { v: 'v1.12.0', date: '2026-06-11', body: "Concurrent waves! You can now start the next wave WHILE one is still running — the Start button becomes ➕ Add Wave, so you can pour up to 3 waves onto the path at the same time for a high-risk rush. Each wave spawns as its own parallel stream. When the field finally clears, every bundled wave pays out its clear bonus and any boss-wave draft you crossed still pops — so rushing never costs you gold or perks, it just throws everything at you at once. (Spacebar adds a wave too.)" },
  { v: 'v1.11.0', date: '2026-06-11', body: "New 🗑 Reset All button on the start screen — wipes everything (chips, talents, achievements, records, your current run, and settings) and starts you completely fresh. It's a two-click confirm so you can't nuke your progress by accident: the first click arms it (turns red, 'Erase ALL — click again'), the second within 3 seconds does the deed." },
  { v: 'v1.10.0', date: '2026-06-11', body: "Spec & poison rework (your feedback) plus polish. Booster's Network now adds +10% aura power on top of its +50% range, so wider coverage no longer means giving up damage. Cannon's Mega Blast gains +15% damage alongside a bigger +60% blast — a real crowd-clear pick vs Cluster's single-target punch. Poison got a serious glow-up: stronger damage-over-time AND its acid now corrodes enemy armor on every hit, melting shielded foes and bosses for the whole team. Frost's Shatter spec was dialed back (×6 → ×4.5 damage) — paired with Frost Mastery it was carrying whole runs solo. Enemies are also tougher: another +25% health on top of last update's bump (still too easy, per your runs). Bug fix: your game-speed setting (1×/2×/3×) now sticks across a refresh/resume — before, reloading silently dropped you to 1×, which made every tower look like it was firing at its base speed. Also: the COMBO timer bar now flashes red as your streak is about to lapse, and the game respects your OS 'reduce motion' setting (skips screen-shake, thins particle bursts)." },
  { v: 'v1.9.2', date: '2026-06-11', body: "Difficulty bump (your feedback — \"the game is still too easy\"): every enemy now has 20% more health, bosses and tanks included. It's a deliberately modest, across-the-board step — towers still clear the early waves comfortably, but a coasting defense will start to feel the squeeze in the mid-to-late game. More tuning to come as the curve gets dialed in." },
  { v: 'v1.9.1', date: '2026-06-11', body: "Tidier tower menu (your feedback): clicking a tower used to pop its upgrade/sell menu right where you clicked, often covering enemies and the action on the path. The menu now sits pinned in the bottom-left corner of the board instead — out of the way of live combat, in the same spot every time. It grows upward so the spec choice at level 5 never gets cut off." },
  { v: 'v1.9.0', date: '2026-06-11', body: "New enemy — the 👻 Phantom! From wave 13 on, ghostly teal blinkers join the line. Every couple of seconds a phantom flickers and teleports a short hop forward — and while it's mid-blink it's intangible, so shots pass right through it. Slow, single-target towers get punished; quick-firing and area towers shine. Listen for the whoosh." },
  { v: 'v1.8.6', date: '2026-06-11', body: "🩺 Health check (every-6th-run maintenance pass): tests all green (123/0), code files all well within size limits, docs verified against the code, and old saves still load correctly. Also added the basics a polished web game should have — a ⚡ favicon in the browser tab, a page description, a mobile-friendly viewport tag, and link-preview (Open Graph) tags. No gameplay changes. Audited the bigger missing pieces (touch controls, gamepad, reduced-motion, PWA install) onto the roadmap." },
  { v: 'v1.8.5', date: '2026-06-11', body: "Combo meter moved to the bottom-right corner (your suggestion): instead of squeezing it into the busy top area — where it kept bumping the boss bar, the 'Wave clear! +bonus' text, and the milestone pop, and was getting clipped against the top edge — the COMBO meter now lives in the empty bottom-right corner with room to breathe. The '🔥 N× COMBO!' milestone pop stays on the center board. No more overlap, anywhere." },
  { v: 'v1.8.4', date: '2026-06-11', body: "Combo pop placement, take two (your feedback): v1.8.3 moved the '🔥 N× COMBO!' milestone pop into the top-left corner — but that's where the COMBO meter itself lived, so they overlapped. The pop now fires on the center board, below the top HUD band. (The meter itself moved to the bottom-right in v1.8.5.)" },
  { v: 'v1.8.3', date: '2026-06-11', body: "Combo meter cleanup (your feedback): the draining timer bar no longer overlaps the word COMBO — the 'COMBO' label now sits to the right of the multiplier with the bar in its own lane below. (The milestone-pop placement from this update was corrected in v1.8.4.)" },
  { v: 'v1.8.2', date: '2026-06-11', body: "More under-the-hood tidy-up: the game's code is now split by domain into seven small files (core/audio, maps, definitions, state, gameplay, update, rendering) instead of one big script. Still zero change for you — double-click tower-defense.html and play exactly as before. Purely a maintainability win." },
  { v: 'v1.8.1', date: '2026-06-11', body: "Under-the-hood tidy-up: the game is now split into separate files — tower-defense.html (markup), tower-defense.css (styles) and the game code — instead of one giant HTML file. Nothing changes for you: just double-click tower-defense.html to play, exactly as before. This makes the codebase easier to maintain going forward." },
  { v: 'v1.8.0', date: '2026-06-11', body: "Combo Master! A new 💥 achievement for reaching a 30× kill-streak in a single run, plus a 🔥 Best combo stat on the Records panel that tracks your all-time highest streak. Chase those chains — the combo system finally pays off your account." },
  { v: 'v1.7.1', date: '2026-06-11', body: "Fix: the new COMBO meter was drawing behind the ability buttons (Meteor / Freeze / Gold Rush) in the top-right corner. Moved it to the top-left of the board so it no longer hides behind your abilities." },
  { v: 'v1.6.1', date: '2026-06-11', body: "New record! flourish — when a quick-mode run beats your best wave for that map × difficulty (your Records cell), the game-over/victory screen now celebrates with a golden banner showing the old→new wave delta, a triumphant fanfare, and a screen-shake + particle burst. First-ever entries record quietly; only beating a real best fires the party." },
  { v: 'v1.5.2', date: '2026-06-11', body: "What's New no longer grows taller than the game on big screens — the panel is now capped to the game's height and scrolls internally, so it stays a tidy window flush beside the board instead of overhanging the bottom." },
  { v: 'v1.5.1', date: '2026-06-11', body: "Cleaner start screen — when no game is running, the stats bar, tower shop, wave controls and hotkey hint now dim out and go non-interactive so the start menu is the only live surface. They light back up the moment you hit Play or resume a run." },
  { v: 'v1.4.1', date: '2026-06-10', body: "What's New now floats beside the ENTIRE game — opening it shifts the whole layout (title, HUD, towers, controls) together instead of only sliding the canvas over. On narrow screens it still tucks below." },
  { v: 'v1.4.0', date: '2026-06-10', body: "Added a What's New side panel (this list — it opens by default, sits flush beside the game, and scrolls; ✕ to hide) plus a version tag on the start screen. Established a headless Playwright test harness so future updates are verified automatically." },
  { v: 'v1.3.x', date: '2026-06', body: 'Removed the Scrapper perk and dropped rare-draft chance from 26% to 14% to make legendary perks feel special again.' },
  { v: 'v1.3.x', date: '2026-06', body: 'Increased enemy HP 20% across all modes and lengthened campaign waves (15 at level 1 up to 54 at level 40).' },
  { v: 'v1.2.0', date: '2026-06', body: 'Campaign mode (40 levels, random maps each attempt), abilities (Meteor / Freeze / Gold Rush), rarity-tiered perk drafts, and the Mayhem map.' },
  { v: 'v1.1.0', date: '2026-06', body: 'Talents and permanent chip progression, tower specializations at max level, difficulties, and save/resume.' },
];
// Open by default; only stays hidden if the player explicitly closes it (persisted).
let wnClosed = localStorage.getItem('cd_wnclosed') === '1';
// "New since last visit" marker (v1.44.0): cd_wnseen stores the newest version the
// player has already seen in the panel. CHANGELOG_ENTRIES is newest-first, so every
// entry ABOVE that version's index is unseen. The key is absent for old saves / new
// players — initWhatsNew() then seeds it to the current version (treat them as caught
// up) so they aren't flooded with a wall of NEW badges; only genuinely-newer updates
// flag from then on. Additive key, swept by resetAllData's cd_-prefix wipe.
function unseenWhatsNewCount() {
  const seen = localStorage.getItem('cd_wnseen');
  if (!seen || !CHANGELOG_ENTRIES.length) return 0;
  const idx = CHANGELOG_ENTRIES.findIndex(e => e.v === seen);
  return idx < 0 ? 0 : idx;   // entries [0..idx) are newer than the last-seen version
}
function markWhatsNewSeen() {
  if (CHANGELOG_ENTRIES.length) {
    try { localStorage.setItem('cd_wnseen', CHANGELOG_ENTRIES[0].v); } catch (e) {}
  }
}
// Update the start-screen "fresh updates" cue: a count pill on the ✨ What's New
// button + a dot on the version tag. Safe to call any time (no-ops if absent).
function refreshWhatsNewBadge() {
  const n = unseenWhatsNewCount();
  const btn = document.getElementById('wnBtn');
  if (btn) btn.innerHTML = "✨ What's New" + (n > 0 ? ` <span class="wnBadge">${n}</span>` : '');
  const vt = document.getElementById('verTag');
  if (vt) vt.classList.toggle('hasNew', n > 0);
}
function renderWnList() {
  const list = document.getElementById('wnList');
  list.innerHTML = '';
  const unseen = unseenWhatsNewCount();   // first `unseen` entries are new since last visit
  CHANGELOG_ENTRIES.forEach((e, i) => {
    const d = document.createElement('div');
    d.className = 'wnEntry' + (i < unseen ? ' wnFresh' : '');
    const when = e.time ? `${e.date} · ${e.time}` : e.date;
    const badge = i < unseen ? '<span class="wnNew">NEW</span>' : '';
    d.innerHTML = `<span class="wnver">${e.v}</span><span class="wndate">${when}</span>${badge}<div class="wnbody">${e.body}</div>`;
    list.appendChild(d);
  });
}
// Cap the panel to the game's height so it never grows past the game — it
// scrolls internally instead (the #gameCol drives the row height since the row
// is align-items:flex-start, so its offsetHeight is the game's natural height).
function syncWhatsNewHeight() {
  const gc = document.getElementById('gameCol');
  const wn = document.getElementById('whatsnew');
  if (!gc || !wn || getComputedStyle(wn).display === 'none') return;
  wn.style.maxHeight = gc.offsetHeight + 'px';
}
function openWhatsNew() {
  renderWnList();   // render BEFORE marking seen so this view still shows the NEW badges
  wnClosed = false;
  localStorage.removeItem('cd_wnclosed');
  localStorage.setItem('cd_wnopen', '1');   // explicit opt-in (drives the small-screen default below)
  const panel = document.getElementById('whatsnew');
  panel.style.display = 'flex';
  syncWhatsNewHeight();
  const list = document.getElementById('wnList');
  if (list) list.scrollTop = 0;   // newest is at the top — start there on open
  markWhatsNewSeen();             // now caught up; clears badges on the next render/load
  refreshWhatsNewBadge();         // drop the start-screen count pill / version dot
}
function closeWhatsNew() {
  wnClosed = true;
  localStorage.setItem('cd_wnclosed', '1');
  localStorage.removeItem('cd_wnopen');
  document.getElementById('whatsnew').style.display = 'none';
}
// Show it on first load (and every load) unless the player closed it before.
// On phones/small tablets (≤920px) the rail stacks full-width BELOW the board and
// buries it ("What's New shown behind the game" — owner FEEDBACK), so there it
// defaults to CLOSED unless the player has explicitly opened it (cd_wnopen). On
// desktop `small` is false, so this is byte-identical to the old open-by-default.
function initWhatsNew() {
  // First encounter (old save / new player): seed cd_wnseen to the current version so
  // the whole back-catalogue isn't flagged NEW. Only updates shipped AFTER this point
  // light up. Must run before any renderWnList so the baseline is in place.
  if (localStorage.getItem('cd_wnseen') === null) markWhatsNewSeen();
  const small = typeof matchMedia === 'function' && matchMedia('(max-width: 920px)').matches;
  const optedIn = localStorage.getItem('cd_wnopen') === '1';
  if (wnClosed || (small && !optedIn)) document.getElementById('whatsnew').style.display = 'none';
  else openWhatsNew();
  refreshWhatsNewBadge();   // reflect any unseen entries on the start-screen cue
}
// Keep the cap in sync as the viewport (and thus the game's height) changes.
window.addEventListener('resize', syncWhatsNewHeight);

// ===== Menu keyboard accessibility (v1.19.0) =====
// The start-screen panels were mouse-only. This makes them keyboard-navigable:
// Esc closes the open panel, Tab is trapped inside the open MODAL panels (so a
// keyboard/screen-reader user can't tab out into the dimmed page behind), and
// focus returns to the button that opened it on close. Pure DOM/UX — no
// gameplay/economy/save impact. The close functions referenced here live in
// later files but resolve at call time (classic scripts share one scope).
// Priority order: modal overlays first, then the non-modal What's New side rail.
const A11Y_PANELS = [
  { id: 'talentPanel',   close: () => closeTalents() },
  { id: 'achPanel',      close: () => closeAchievements() },
  { id: 'bestPanel',     close: () => closeBests() },
  { id: 'settingsPanel', close: () => closeSettings() },
  { id: 'whatsnew',      close: () => closeWhatsNew(), nontrap: true },
];
const FOCUSABLE_SEL = 'button, [href], input, select, textarea, [tabindex]:not([tabindex="-1"])';
// Visible via computed display — NOT offsetParent, which is null for the
// position:fixed panels of the mobile (≤920px) layout, so Esc would silently
// no-op on phones if we keyed off offsetParent here.
function panelOpen(el) { return !!el && getComputedStyle(el).display !== 'none'; }
function focusablesIn(el) {
  return Array.prototype.slice.call(el.querySelectorAll(FOCUSABLE_SEL))
    .filter(n => n.offsetParent !== null && !n.disabled);
}
let _panelOpener = null;
// Move focus into a just-opened modal panel, remembering the opener to restore later.
function focusPanel(id) {
  const el = document.getElementById(id);
  if (!el) return;
  const a = document.activeElement;
  _panelOpener = (a && a !== document.body) ? a : null;
  const f = focusablesIn(el);
  if (f.length) f[0].focus();
}
function _topTrapPanel() {          // highest-priority open panel that traps Tab (excludes the rail)
  // The mid-game perk draft (v1.20.0) traps Tab too, but is deliberately absent
  // from A11Y_PANELS so Esc can't close it (a pick is required). It's a forced
  // modal during gameplay, so it outranks any start-screen panel when open.
  const draft = document.getElementById('draftModal');
  if (panelOpen(draft)) return draft;
  for (const p of A11Y_PANELS) { if (p.nontrap) continue; const el = document.getElementById(p.id); if (panelOpen(el)) return el; }
  return null;
}
function _topAnyPanel() {           // highest-priority open panel incl. the rail (for Esc)
  for (const p of A11Y_PANELS) { const el = document.getElementById(p.id); if (panelOpen(el)) return p; }
  return null;
}
function _restoreOpenerFocus() {
  if (_panelOpener && _panelOpener.offsetParent !== null) { try { _panelOpener.focus(); } catch (e) {} }
  _panelOpener = null;
}
document.addEventListener('keydown', e => {
  if (e.key === 'Escape') {
    const top = _topAnyPanel();
    if (top) { e.preventDefault(); e.stopPropagation(); top.close(); _restoreOpenerFocus(); }
    return;
  }
  if (e.key === 'Tab') {
    const panel = _topTrapPanel();
    if (!panel) return;
    const f = focusablesIn(panel);
    if (!f.length) return;
    const first = f[0], last = f[f.length - 1], a = document.activeElement;
    if (!panel.contains(a)) { e.preventDefault(); first.focus(); }
    else if (e.shiftKey && a === first) { e.preventDefault(); last.focus(); }
    else if (!e.shiftKey && a === last) { e.preventDefault(); first.focus(); }
  }
});

// ================= Audio =================
let audioCtx = null;
let muted = localStorage.getItem('cd_mute') === '1';
let lastShootSfx = 0;
// Master volume (0..1), persisted as cd_vol (Settings panel, v1.13.2). All tone()/
// noise() output routes through a single master GainNode so the slider scales everything.
let masterVol = (() => { const v = localStorage.getItem('cd_vol'); return v === null ? 0.7 : Math.max(0, Math.min(1, +v || 0)); })();
let _masterGain = null;
function ac() {
  if (!audioCtx) audioCtx = new (window.AudioContext || window.webkitAudioContext)();
  return audioCtx;
}
function masterGain() {
  const a = ac();
  if (!_masterGain) { _masterGain = a.createGain(); _masterGain.gain.value = masterVol; _masterGain.connect(a.destination); }
  return _masterGain;
}
function setVolume(pct) {   // pct is 0..100 from the slider
  masterVol = Math.max(0, Math.min(1, (+pct || 0) / 100));
  try { localStorage.setItem('cd_vol', String(masterVol)); } catch(e) {}
  if (_masterGain) _masterGain.gain.value = masterVol;
}
function tone(freq, dur, type='square', vol=0.08, slide=0) {
  if (muted) return;
  try {
    const a = ac();
    const o = a.createOscillator(), g = a.createGain();
    o.type = type; o.frequency.value = freq;
    if (slide) o.frequency.exponentialRampToValueAtTime(Math.max(30, freq+slide), a.currentTime + dur);
    g.gain.setValueAtTime(vol, a.currentTime);
    g.gain.exponentialRampToValueAtTime(0.0001, a.currentTime + dur);
    o.connect(g); g.connect(masterGain());
    o.start(); o.stop(a.currentTime + dur);
  } catch(e) {}
}
let noiseBuf = null;
function noise(dur, vol, filterType='lowpass', freq=1000, slide=0, Q=1, delay=0) {
  if (muted) return;
  try {
    const a = ac();
    if (!noiseBuf) {
      noiseBuf = a.createBuffer(1, a.sampleRate, a.sampleRate);
      const d = noiseBuf.getChannelData(0);
      for (let i = 0; i < d.length; i++) d[i] = Math.random()*2 - 1;
    }
    const t0 = a.currentTime + delay;
    const src = a.createBufferSource();
    src.buffer = noiseBuf; src.loop = true;
    src.playbackRate.value = 0.7 + Math.random()*0.6;
    const f = a.createBiquadFilter();
    f.type = filterType; f.frequency.setValueAtTime(freq, t0); f.Q.value = Q;
    if (slide) f.frequency.exponentialRampToValueAtTime(Math.max(40, freq + slide), t0 + dur);
    const g = a.createGain();
    g.gain.setValueAtTime(vol, t0);
    g.gain.exponentialRampToValueAtTime(0.0001, t0 + dur);
    src.connect(f); f.connect(g); g.connect(masterGain());
    src.start(t0); src.stop(t0 + dur);
  } catch(e) {}
}
